import layout from '../_components/layout'
import sellerplan from '../_components/seller-plan'
import choosingplan from '../_components/choosingplan'
import addshoptifystore from '../_components/add-shoptify-store'
import FavoriteCategory from '../_components/favorite-category'
import successplaning from '../_components/success-planing'
import forgotPassword from '../_components/forgot-password'
import activeEmail from '../_components/active-email-success'

// import Index  from '../_components/'
import Account from '../_components/account'
import YourStore from '../_components/your-store'
import Subscription from '../_components/subscription'
import Pricing from '../_components/pricing'
import YourCategories from '../_components/category'
import BecomeSupplier from '../_components/become-supplier'
import Login from '../_components/login'

export default {
    path: '/seller',
    component: layout,
    meta: {
        requiresAuth: true,
        roles: [],
    },
    children: [
        {
            path: '',
            name: 'Seller',
            component: Account,
            meta: {
                title: "Account"
            },
        },
        {
            path: 'your-store',
            name: 'YourStore',
            component: YourStore,
            meta: {
                title: "Your Store"
            },
        },
        {
            path: 'subscription',
            name: 'Subscription',
            component: Subscription,
            meta: {
                title: "Subscription"
            },
        },
        {
            path: 'pricing',
            name: 'Pricing',
            component: Pricing,
            meta: {
                title: "Pricing"
            },
        },
        {
            path: 'your-categories',
            name: 'YourCategories',
            component: YourCategories,
            meta: {
                title: "Your Categories"
            },
        },
        {
            path: 'become-supplier',
            name: 'BecomeSupplier',
            component: BecomeSupplier,
            meta: {
                title: "Become Supplier"
            },
        },
        {
            path: 'login',
            name: 'Login',
            component: Login,
            meta: {
                requiresAuth: false,
                failback: true,
            },
        },
        {
            path: 'sellerplan',
            component: sellerplan,
            meta: {
                checkPlan: true
            },
            children: [
                {
                    path: '',
                    name: 'SellerPlan',
                    component: choosingplan,
                    meta: {},
                }, {
                    path: 'add-shoptify-store',
                    name: 'AddShoptifyStore',
                    component: addshoptifystore,
                    meta: {},
                }, {
                    path: 'favorite-category',
                    name: 'ChoosingFavoriteCategory',
                    component: FavoriteCategory,
                    meta: {},
                }, {
                    path: 'success-planing',
                    name: 'SuccessPlaning',
                    component: successplaning,
                    meta: {},
                },
            ]
        },
        {
            path: 'login/reset',
            name: 'ResetPassword',
            component: forgotPassword,
            meta: {
                requiresAuth: false,
                failback: true,
            },
        },
        {
            path: 'active',
            name: 'ActiveEmail',
            component: activeEmail,
            meta: {
                requiresAuth: false,
                failback: true,
            },
        }
    ],
}

