<template>
    <div>
        
        <div class="product-filter-title m-b-25">
            <span>{{ $t('auth.form.forgot-password.title') }}</span>
        </div>
        
        <template v-if="!isSentForgotEmail">
            <p>{{ $t('auth.form.forgot-password.description') }} </p>
            <form @submit.stop.prevent="submit()" novalidate autocomplete="off">
                <div class="form-group become-input">
                    <label class="input-title">{{ $t('auth.form.forgot-password.email') }} <span class="text-danger">*</span></label>
                    <input class="form-control" v-model="$v.form.email.$model" :placeholder="$t('auth.form.forgot-password.email-placeholder')" :class="{'is-invalid': $v.form.email.$invalid && formstate }" />
                    <transition name="fade" mode="out-in">
                        <div class="text-danger m-t-10" v-if="$v.form.email.$invalid && formstate">
                            <p v-if="!$v.form.email.required"> {{ $t('auth.form.forgot-password.email-required') }} </p>
                            <p v-if="!$v.form.email.email"> {{ $t('auth.form.forgot-password.email-type') }} </p>
                        </div>
                    </transition>
                    <transition name="fade" mode="out-in">
                        <div class="text-danger m-t-10" v-if="error">
                            <p > {{ error }} </p>
                        </div>
                    </transition>
                </div>
                <div class="text-right">
                    <a href="#" @click.stop.prevent="changeMode()" class="text-yellow forgot-password">{{ $t('auth.form.forgot-password.back') }}</a>
                </div>
                <div class="form-action ">
                    <button class="save-login btn btn-warning btn-radius-border" type="submit" >
                        <transition name="fade" mode="out-in">
                            <span class="icon-loading small" v-if="isLoading" key="isloading"></span>
                        </transition>
                        {{ $t('auth.form.forgot-password.submit') }}
                    </button>
                </div>
            </form>
        </template>
        <template v-else>
            <p class="sent-success-title m-t-60">
                {{ $t('auth.form.forgot-password.success-message') }}
            </p>
            <div class="sent-success">
                <p class="sent-success-description">
                    <a href="#" @click.stop.prevent="changeMode()" class="text-yellow forgot-password">{{ $t('auth.form.forgot-password.back') }}</a>
                </p>
            </div>
        </template>
        
    </div>
</template>
<script>
import { mapActions } from 'vuex';
import {required, minLength, email, sameAs} from 'vuelidate/lib/validators'
export default {
    name : 'ForgotPassword',
    props:{
        mode : {
            required : true,
            type : Boolean
        }
    },
    data(){
        return {
            isSentForgotEmail : false,
            form :{
                email : '',
            },
            isLoading : false,
            formstate : false,
            error : null
        }
    },
    watch :{
        'form' : {
            handler : function(value){
                if( this.error ){
                    this.error = null
                }
            },
            deep : true
        }
    },
    methods:{
        ...mapActions({
            sentForgotPasswordRequest: "$_Seller/FORGOT_PASSWORD",
        }),
        changeMode(){
            this.$emit('update:mode' , true)
        },
        submit(){
            this.formstate = true 
            if( !this.$v.form.$invalid && !this.isLoading ){
                this.isLoading = true
                this.sentForgotPasswordRequest({
                    email: this.form.email
                }).then(res => {
                    this.isLoading = false
                    let {status, message} = res.data
                    if (status) {
                        this.isSentForgotEmail = true
                    } else {
                        this.error = message ? message : 'error'
                    }
                }, error =>{
                    this.isLoading = false
                })
            }
        }
    },
    validations(){
        return {
            form : {
                email : { required , email }
            }
        }
    }
}
</script>
