<template>
	<div class="app-collection">
        
            <transition name="fade-transform" mode="out-in">
                <div class="app-collection-container" v-if="error" key="is-load-error">
                    <div class="container">
                        <div class="app-collection-row row" >
                            <div class="col col-12">
                                <error></error>
                            </div>
                        </div>
                    </div>
                </div>
                <div class="app-collection-container" v-else key="is-load-success">
                    <div class="app-collection-container-breadcrumb">
                        <div class="container">
                            <div class="row">
                                <div class="col col-12">
                                    <breadcrumb :data="cumputeCollection.title"></breadcrumb>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="container p-b-30 p-t-30">
                        <div class="app-collection-row row" >
                            <div class="app-collection-col app-collection-col-sidebar col">
                                <app-sidebar :list="cumputeCollection"></app-sidebar>
                            </div>
                            <div class="app-collection-col app-collection-col-content col">
                                <tab-filter-router></tab-filter-router>
                                <transition name="fade-transform" mode="out-in">
                                    <div class="row" v-if="isLoading" key="list-product-loading">
                                        <div class="col col-12">
                                            <product-loading :limit="pagination.limit" col="col col-md-4 col-lg-3 m-b-30"></product-loading>
                                        </div>
                                    </div>
                                    <div  v-else key="row list-product-ready">
                                        <template v-if="products.length">
                                            <list-products :products="products" col="col col-md-4 col-lg-3 m-b-30" :has-banner="false"></list-products>
                                            <div class="text-center">
                                                <pagination v-model="pagination.current_page" :total="pagination.total_page"></pagination>
                                            </div>
                                        </template>
                                        <template v-else>
                                            <div class="col col-12 ">
                                                <product-empty>
                                                    <p>Sorry, we couldn't find any content </p>
                                                </product-empty>
                                            </div>
                                        </template>
                                    </div>
                                </transition>
                            </div>
                        </div>
                    </div>
                 </div>
            </transition>
    </div>
</template>
<script>
    import ProductEmpty from '../partials/product-empty'
    import ProductLoading from '../partials/product-loading'
    import ListProducts from '../partials/list-products'
    import AppSidebar from '../partials/sidebar'
    import TabFilterRouter from '../partials/tab-filter-router'
    import { mapGetters } from 'vuex';
    import helper from '@/plugins/helper'
    import Pagination  from '@/components/pagination'
    import error from '@/components/error-404'
    import breadcrumb from '../partials/collection-breadcrumb'
	export default{
        name : 'Collections',
        components: {
            AppSidebar , TabFilterRouter ,ListProducts , Pagination , ProductEmpty , ProductLoading ,error , breadcrumb
        },
        metaInfo() {
            return {
                title: this.meta.title,
            }
        },
        data(){
            return {
                isLoading: false,
                sortables : ['last' ,'trending' ,'price'],
                collection_id : '',
                products : [],
                default_sort : 'last',
                meta:{
                    title : 'All Collections'
                },
                pagination : {
                    limit : 20,
                    total : 0,
                    total_page : 0,
                    current_page : 1,
                },
                error : false,
                selectedCollection : null
            }
        },
        computed: {
            ...mapGetters({
                collections : '$_Home/getCollections',
                countries : '$_Home/getCountries'
            }),
            cumputeCollection(){
                let collection_id = this.$route.params.id   ? this.$route.params.id : null
                if( collection_id ){
                    collection_id = this.getSlugId(collection_id)
                    var collection = helper.findDeep(this.collections , 'id' , (item , id ) => id == collection_id)
                    if( collection ){
                        if( collection.level == 1){
                            return {
                                title : [
                                    {
                                        id : collection.id,
                                        title : collection.title,  
                                    }
                                ],
                                list : collection.childs,
                                selected : collection.title,
                                hasChild : collection.childs ? true : false
                            }
                        }else if( collection.level == 2){
                            var object = {
                                title : [],
                                list : [],
                                selected : collection.title,
                                hasChild : collection.childs ? true : false
                            }
                            var level1 = helper.findDeep(this.collections , 'id' , (item , id ) => id == collection.parent_id)
                            if( level1 ){
                                object.title.push({
                                    id : level1.id,
                                    title : level1.title
                                })
                            }
                            object.title.push({
                                id : collection.id,
                                title : collection.title
                            })
                            if( collection.childs ){
                                object.list = collection.childs
                            }
                            return object
                        }else if( collection.level == 3){
                            var object = {
                                title : [],
                                list : [],
                                selected : collection.title,
                                hasChild : collection.childs ? true : false
                            }
                            var level2 = helper.findDeep(this.collections , 'id' , (item , id ) => id == collection.parent_id)
                            if( level2 ){
                                var level1 = helper.findDeep(this.collections , 'id' , (item , id ) => id == level2.parent_id)
                                if( level1 ){
                                    object.title.push({
                                        id : level1.id,
                                        title : level1.title
                                    })
                                }
                                object.title.push({
                                    id : level2.id,
                                    title : level2.title
                                })
                            }
                            object.title.push({
                                id : collection.id,
                                title : collection.title
                            })
                            return object
                        }
                        
                    }
                }else{
                    return {
                        title : [],
                        list : this.collections,
                        selected : null,
                        hasChild : true
                    }
                }
            }
        },
        methods: {
            getProduct(to = null){
                if( to == null){
                    to = this.$route
                }
                let sort = to.query.sort ? to.query.sort : null 
                sort = this.checkSort(sort) ? sort : this.default_sort
                /* get current_page */
                let page = to.query.page   ? to.query.page : 1
                if( page ) {
                    page = helper.isNumeric(page) ? page : 1
                }
                /* get collection_id */
                let collection_id = to.params.id   ? to.params.id : null
                if( collection_id ) {
                    collection_id = this.getSlugId(collection_id)
                    var collection = helper.findDeep(this.collections , 'id' , (item , id ) => id == collection_id)
                    if( collection ){
                        this.setMeta(collection)
                    }else{
                        // this.error = true
                        // return;
                    }
                }
                /* get supplier_id */
                let supplier_id = to.query.supplier_id  ? to.query.supplier_id : null 
                if( supplier_id ) {
                    supplier_id = this.checkSupplier(supplier_id) ? supplier_id : null
                }
                /* get shipping_from */
                let shipping_from = to.query.shipping_from ?  to.query.shipping_from : null
                if( shipping_from ){
                    shipping_from = this.checkCountry(shipping_from) ? shipping_from : null
                }
                /* get shipping_to */
                let shipping_to = to.query.shipping_to  ? to.query.shipping_to : null
                if( shipping_to ){
                    shipping_to = this.checkCountry(shipping_to) ? shipping_to : null
                }
                /* get prices */
                let prices = null
                let price = to.query.prices 
                if( price ){
                    var temp = price.split('-')
                    if( temp.length == 2){
                        var min = temp[0].trim()
                        var max = temp[1].trim()
                        if( helper.isNumeric(min) && helper.isNumeric(max) && parseInt(min) <= parseInt(max)){
                            prices = price
                        }
                    }
                }
                return new Promise((resolve , reject )=>{
                    this.$store.dispatch('$_Home/GET_LIST_PRODUCTS' , { 
                        sort : sort,
                        collection_id: collection_id,
                        page : page,
                        supplier_id: supplier_id,
                        shipping_from : shipping_from,
                        shipping_to : shipping_to,
                        prices : prices,
                        limit : this.pagination.limit,
                    }).then(res=>{
                        let { status , data , pagination } = res
                        if( status ){
                            this.products = data
                            this.pagination.total = parseInt(pagination.total) 
                            this.pagination.total_page = parseInt(pagination.total_page ) 
                            this.pagination.current_page = parseInt(pagination.current_page) 
                            
                        }
                    })
                    resolve()
                })
            },
            checkCountry(code){
                return  _.find(this.countries , { code : code}) != undefined
            },
            checkSupplier(id){
                return _.find(this.suppliers , { id : id}) != undefined
            },
            checkSort(sort){
                return this.sortables.indexOf(sort) >= 0 
            },
            setMeta(collection){
                if( collection ){
                    this.meta.title = collection.title
                }
            },
        },
        beforeRouteUpdate : async function(to, from, next) {
            this.isLoading = true
            await this.getProduct(to)
            this.isLoading = false
            next()
        },
        created : async function(){
            this.isLoading = true
            var to = this.$route
            var collection_id = this.getSlugId(to.params.id)
            var findIndex = _.findIndex(this.collections , { id : collection_id})
            if( findIndex >= 0 ){
                var more = findIndex >= 10 ? true : false
                this.$store.commit('$_Home/UPDATE_SIDEBAR_OPTION' , { collection_id : '' , more : more})
            }else{
                for (let index = 0; index < this.collections.length; index++) {
                    const collection = this.collections[index]
                    var child = _.find( collection.childs , {id : collection_id})
                    if( child ){
                        var more = index >= 10 ? true : false
                        this.$store.commit('$_Home/UPDATE_SIDEBAR_OPTION' , { collection_id : child.parent_id , more : more})
                        break
                    }
                }
            }
            this.$store.commit('$_Home/UPDATE_SIDEBAR_OPTION' , { collection_id : '' , more : false})
            await this.getProduct(this.$route)
            this.isLoading = false
        }
    }
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-collection{
        
        &-container{
            &-breadcrumb{
                background: #f2f2f2;
                padding: 15px 0;
            }
        }
        &-row{

        }
        &-col{
            &-sidebar{
                max-width: 20%;
            }
            &-content{
                max-width: 80%;
            }
        }
    }
</style>