<template>
    <div class="product-item" itemscope>
        <div class="product-item-img">
            <div class="product-image">
                <div class="product-image-box">
                    <template v-if="ProductInfo.image">
                        <img itemprop="image" :src="ProductInfo.image" :title="ProductInfo.title"
                             :alt="ProductInfo.image">
                    </template>
                    <template v-else>
                        <img itemprop="image" src="@/assets/images/default/product.png" :title="ProductInfo.title"
                             :alt="ProductInfo.image">
                    </template>
                </div>
            </div>
            <div class="product-action">
                <div class="action-btn-container">
                    <span>SEE DETAIL</span>
                    <button class="btn btn-outline-warning btn-radius-border btn-quick-view"
                            @click.stop.prevent="showQuickView()">
                        Quick view
                    </button>
                    <button v-if="!ProductInfo.isImported" v-on:click="importProduct(ProductInfo, $event)"
                            :class="{'btn-importing': isLoading}" class="btn black-button-style btn-radius-border">
                        <i class="icon-load fas fa-shopping-bag"></i>
                        <div class="circle-loader">
                            <div class="checkmark draw"></div>
                        </div>
                        Add to Import List
                    </button>
                    <button v-else :class="{'btn-importing': isLoading}"
                            v-on:click="removeImported(ProductInfo, $event)" class="btn btn-warning btn-radius-border">
                        <i class="icon-load fas fa-trash"></i>
                        <div class="circle-loader">
                            <div class="checkmark draw"></div>
                        </div>
                        Remove imported
                    </button>
                </div>
            </div>
        </div>
        <div class="product-item-info">
            <router-link class="product-name" :to="setRouterLink()" :title="ProductInfo.title" itemprop="url">
                <h3 itemprop="name" v-line-clamp:20="2">{{ProductInfo.title}}</h3>
            </router-link>
            <div class="product-supplier">
                By <span>{{ProductInfo.shop_name}}</span>
            </div>
            <div class="product-price" itemprop="offers">
                <template v-if="ProductInfo.price_min == ProductInfo.price_max">
                    <span itemprop="priceCurrency" content="USD">$</span>
                    <span itemprop="price" :content="ProductInfo.price_max | number_format">{{ ProductInfo.price_max | number_format}}</span>
                </template>
                <template v-else>
                    <span>
                        <span itemprop="priceCurrency" content="USD">$</span>
                        <span itemprop="lowPrice" :content="ProductInfo.price_min | number_format">{{ ProductInfo.price_min | number_format}}</span>
                    </span>
                    -
                    <span>
                        <span itemprop="priceCurrency" content="USD">$</span>
                        <span itemprop="highPrice" :content="ProductInfo.price_max | number_format">{{ ProductInfo.price_max | number_format}}</span>
                    </span>
                </template>
            </div>

        </div>
    </div>
</template>

<script>
    import {mapActions, mapGetters} from 'vuex'

    export default {
        name: "Product",
        props: {
            ProductInfo: {
                type: Object,
                required: true,
            }
        },
        data() {
            return {
                isLoading: false
            }
        },
        computed : {
            ...mapGetters({
                seller: '$_Seller/getSeller',
            }),
        },
        methods: {
            ...mapActions({
                callImportProduct: "$_Home/IMPORT_PRODUCT",
                removeImportedProduct: "$_Home/REMOVE_IMPORTED_PRODUCT",
            }),
            
            importProduct(product, event) {
                if (this.seller) {
                    let id = product.id
                    let target = $(event.target)
                    this.isLoading = true
                    let defaultShop = this.seller.shops.filter(function (el, idx) {
                        return el.shop_default == 1
                    });
                    let temp = {
                        "product_id": id,
                        "shop_id": defaultShop[0].id
                    }
                    this.callImportProduct(temp).then(res => {
                        if (res.data.status) {
                            this.ProductInfo.isImported = true
                        } else {
                            $notify({
                                content: 'import product fail',
                                type: 'danger'
                            })
                        }
                        this.isLoading = false
                    })
                } else {
                    this.$router.push({
                        name: "Login"
                    })
                }
            },
            removeImported(product) {
                let id = product.id
                let target = $(event.target)
                this.isLoading = true
                let defaultShop = this.seller().shops.filter(function (el, idx) {
                    return el.shop_default == 1
                });
                let temp = {
                    "product_id": id,
                    "shop_id": defaultShop[0].id
                }
                this.removeImportedProduct(temp).then(res => {
                    if (res.data.status) {
                        this.ProductInfo.isImported = false
                    } else {
                        $notify({
                            content: 'Remove Imported Product fail',
                            type: 'danger'
                        })
                    }
                    this.isLoading = false
                })
            },
            setRouterLink() {
                return {
                    name: 'ProductDetail',
                    params: {
                        id: `${this.ProductInfo.handle}-${this.ProductInfo.id}`
                    }
                }
            },
            showQuickView() {
                if (EventBus) {
                    EventBus.$emit('show-quick-view', {id: this.ProductInfo.id})
                }
            }
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';

    $border-color: #eee;
    .product-item {
        height: 100%;
        width: 100%;
        border: solid 1px $border-color;
        // padding: 12.5px;
        padding: 0;
        &-img {
            margin-bottom: 10px;
            position: relative;
            overflow: hidden;
            .product-image {
                &-box {
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    bottom: 0;
                    width: 100%;
                    height: 100%;
                    overflow: hidden;
                    display: flex;
                    flex-direction: row;
                    justify-content: center;
                    align-items: center;
                    padding: 10px;
                    img {
                        // width: 100%;
                        max-height: 100%;
                        max-width: 100%;
                        overflow: hidden;
                    }
                }

                width: 100%;
                height: auto;
                position: relative;
                &:after {
                    content: '';
                    display: block;
                    padding-bottom: 100%;
                }
            }
            .product-action {
                padding: 7px;
                background: rgba(255, 255, 255, 0.6);
                width: 100%;
                height: 100%;
                position: absolute;
                top: 0px;
                left: -100%;
                transition: all .4s;
                .product-sale-tag {
                    background: $yellow;
                    color: white;
                    padding: 0 6px;
                    margin-top: 8px;
                }
                .action-btn-container {
                    position: relative;
                    top: 50%;
                    transform: translateY(-50%);
                    vertical-align: middle;
                    text-align: center;
                    user-select: none;
                    button {
                        font-size: 13px;
                        display: block;
                        margin: auto;
                        text-align: center;
                        margin-bottom: 13px;
                        width: 80%;
                        max-width: 150px;
                        white-space: nowrap;
                        text-overflow: ellipsis;
                        overflow: hidden;
                        &.btn-importing {
                            .icon-load {
                                display: none;
                            }
                            .circle-loader {
                                display: inline-block;
                            }
                        }
                    }
                    span {
                        font-size: 25px;
                        color: #999;
                        font-weight: bold;
                        text-transform: uppercase;
                        display: inline-block;
                    }
                    .btn {
                        &-quick-view {
                            background: #fff;
                            border: 1px solid $yellow;
                            color: $yellow;
                            &:hover {
                                background: $yellow;
                                color: #fff;
                            }
                        }
                    }
                }
            }
            &:hover {
                .product-action {
                    left: 0;
                }
            }
        }
        &-info {
            text-align: center;
            padding: 10px;
            .product-name {
                font-size: $default-font-size;
                color: $text-color;
                margin-bottom: 5px;
                &:hover {
                    color: $yellow;
                }
                h3 {
                    font-size: 14px;
                    margin: 0;
                }
            }
            .product-supplier {
                font-size: 13px;
                color: #999;
                span {
                    color: $yellow;
                }
            }
            .product-price {
                font-size: 16px;
                font-weight: bold;
            }
        }
    }
</style>
