<template>
    <div class="container">
        <div class="success-planning-title m-b-40">
            <span class="big-title">Thank you for choosing Dropsquare</span>
            <span class="small-title">
            <router-link class="text-warning" :to="{name: 'Home'}">
                Let's get started
            </router-link>
            </span>
        </div>
    </div>
</template>

<script>
    import {mapActions} from 'vuex'

    export default {
        name: "forgot-password",
        data() {
            return {
                token: ''
            }
        },
        methods: {
            ...mapActions({
                checkToken: "$_Seller/CHECK_NEW_EMAIL_TOKEN",
            }),
        },
        created: function () {
            let token = this.$route.query['id']
            this.token = token
            console.log(token);
            this.checkToken(token).then(res => {
                if (!res.data.status) {
                    this.redirect({
                        name: 'Error404'
                    })
                } else {
                    this.$store.commit('$_Seller/LOGIN_SUCCESS', {
                        token : res.data.data.token
                    })
                }
            })
        }
    }
</script>

<style lang="scss" scoped>
    .success-planning-title {
        text-align: center;
        .big-title {
            font-size: 35px;
            display: block;
        }
        .small-title {
            color: #989898;
            font-size: 20px;
            display: block;
        }
    }
</style>
