<template>
    <div class="app-product-body-html" :style="setStyle" :class="{ 'is-show' : !collapsed && !isOverflow }">
        <div ref="box" class="app-product-body-html-content" v-html="data"></div>
        <div class="app-product-body-html-read-more" v-if="isOverflow">
            <button class="btn btn-readmore" @click.stop.prevent="toggle()">
                <template v-if="collapsed">
                    Expand
                </template>
                <template v-else>
                    Collapse
                </template>
            </button>
        </div>
    </div>
</template>
<script>
export default {
    name : 'ProductBodyHtml',
    props : {
        data :{
            required : true,
            type : String
        },
        height : {
            type : Number,
            default : 300
        }
    },
    data(){
        return {
            isOverflow: false,
            collapsed : true,
        }
    },
    methods:{
        toggle(){
            this.collapsed = !this.collapsed
        }
    },
    computed:{
        setStyle(){
            if( this.isOverflow  && this.collapsed){
                return {
                    maxHeight : `${this.height}px`
                }
            }
            return {}
        }
    },
    mounted(){
        var height = this.$refs.box.clientHeight
        if( height > this.height){
            this.isOverflow = true
        }
    }
}
</script>
<style lang="scss">
    .app-product-body-html{
        position: relative;
        overflow: hidden;
        
        &-content{
            height: auto;
            img{
                max-width: 100%;
            }
        }
        &-read-more{
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            width: 100%;
            height: 130px;
            padding-top: 85px;
            text-align: center;
            background: rgba(255,255,255,0);
            background: -moz-linear-gradient(top,rgba(255,255,255,0) 0%,rgba(255,255,255,.91) 50%,rgba(255,255,255,1) 55%);
            background: -webkit-gradient(left top,left bottom,color-stop(0%,rgba(255,255,255,0)),color-stop(50%,rgba(255,255,255,.91)),color-stop(55%,rgba(255,255,255,1)));
            background: -webkit-linear-gradient(top,rgba(255,255,255,0) 0%,rgba(255,255,255,.91) 50%,rgba(255,255,255,1) 55%);
            background: -o-linear-gradient(top,rgba(255,255,255,0) 0%,rgba(255,255,255,.91) 50%,rgba(255,255,255,1) 55%);
            background: -ms-linear-gradient(top,rgba(255,255,255,0) 0%,rgba(255,255,255,.91) 50%,rgba(255,255,255,1) 55%);
            background: linear-gradient(to bottom,rgba(255,255,255,0) 0%,rgba(255,255,255,.91) 50%,rgba(255,255,255,1) 55%);
            filter: progid:DXImageTransform.Microsoft.gradient(startColorstr='#ffffff',endColorstr='#ffffff',GradientType=0);
        }
    }
</style>
