<template>
    <div class="account-container">
        <div class="account-form-container row">
            <div class="form-group col col-5">
                <label class="input-title">Email</label>
                <input readonly class="form-control outline-type" v-model="accountInfo.email"/>
            </div>
            <div class="form-group col col-md-5">
                <label class="input-title">Country*</label>
                <div class="outline-type select-outline">
                    <select class="form-control" v-model="accountInfo.country_code">
                        <option v-for="(item , index) in countries" :value="item.code" :key="`item${index}`">
                            {{item.name}}
                        </option>
                    </select>
                </div>
            </div>
            <div class="form-group col col-5">
                <label class="input-title">Password</label>
                <input class="form-control outline-type" type="password" :class="{
                        'is-invalid': !account_validate.password,
                    }" v-model="accountInfo.password"/>
                <div class="invalid-feedback">
                    <span>Password and confirm password must be same</span>
                </div>
            </div>
            <div class="form-group col col-5">
                <label class="input-title" type="password">Confirm Password</label>
                <input class="form-control outline-type" type="password" :class="{
                        'is-invalid': !account_validate.repassword,
                    }" v-model="accountInfo.repassword"/>
                <div class="invalid-feedback">
                    <span>Password and confirm password must be same</span>
                </div>
            </div>
            <div class="form-group col col-5">
                <label class="input-title">Current Password</label>
                <input class="form-control outline-type" type="password" :class="{
                        'is-invalid': !account_validate.current_password,
                    }" v-model="accountInfo.current_password"/>
                <div class="invalid-feedback">
                    <span>Current password is require</span>
                </div>
            </div>
        </div>

        <div class="account-action">
            <button class="update-profile-btn btn btn-warning btn-radius-border" @click="updateAccountInfo">Update
                Profile
            </button>
            <button class="btn">Cancel</button>
        </div>
    </div>
</template>

<script>
    import {mapGetters, mapActions} from 'vuex';

    export default {
        name: "account",
        data() {
            return {
                accountInfo: {
                    country_code: "US",
                    password: '',
                    repassword: '',
                    current_password: '',
                    email: ''
                },
                account_validate: {
                    password: true,
                    repassword: true,
                    current_password: true
                }
            }
        },
        computed: {
            ...mapGetters({
                countries: '$_Home/getCountries'
            })
        },
        methods: {
            ...mapActions({
                updateSellerInfo: '$_Seller/UPDATE_USER_INFO',
                getSellerInfo: "$_Seller/GET_USER_INFO"
            }),
            updateAccountInfo: function () {
                this.validateUserInfo()
                let isValidate = true;
                for (let key in this.account_validate) {
                    if (!this.account_validate[key]) {
                        isValidate = false
                    }
                }
                if (isValidate) {
                    console.log(this.accountInfo);
                    this.updateSellerInfo(this.accountInfo).then((res) => {
                        // after update here
                        console.log(res);
                        if (res.data.status) {
                            $notify({
                                content: "Update success",
                                type: "success"
                            })
                        } else {
                            $notify({
                                content: res.data.message,
                                type: "danger"
                            })
                        }
                        this.resetUserInfo()
                    })
                }
            },
            validateUserInfo() {
                this.account_validate.repassword = (this.accountInfo.password == this.accountInfo.repassword) && (this.accountInfo.password.length >= 6 || this.accountInfo.password.length == 0)
                this.account_validate.password = (this.accountInfo.password == this.accountInfo.repassword) && (this.accountInfo.password.length >= 6 || this.accountInfo.password.length == 0)
                this.account_validate.current_password = this.accountInfo.current_password.length >= 6
            },
            initUserInfo() {
                this.getSellerInfo().then(res => {
                    if (res.status) {
                        this.accountInfo = {...this.accountInfo,...res.data.data}
                    } else {
                        $notify({
                            content: "Load Seller info Fail",
                            type: "danger"
                        })
                    }
                })
            },
            resetUserInfo() {
                this.accountInfo.password = ''
                this.accountInfo.repassword = ''
                this.accountInfo.current_password = ''
            }
        },
        created: function () {
            // this.initUserInfo()
            var seller = this.$store.getters['$_Seller/getSeller']
            if( seller ){
                this.accountInfo = {...this.accountInfo,...seller}
            }
        },
        watch: {
            "accountInfo":{
                handler(val){
                    // do stuff
                },
                deep: true
            }
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';

    .account-container {
        .title-container {
            margin-bottom: 40px;
        }
        .form-group {
            margin-bottom: 30px;
            input, .select-outline {
                height: 45px;
            }
        }
        .update-profile-btn {
            color: white;
        }
    }

</style>
