<template>
    <div>
        <div class="plan-description m-b-40"><span>Your acccount has been verified. Please select your plan</span></div>
        <div>
            <pricing @choose_plan="choosePlan" :isNotAuto="true"></pricing>
        </div>
        <carddialog :isShow="isCardDialogShow" @modalHide="isCardDialogShow=false" @dialogConfirm="createCardForCustomer"></carddialog>
    </div>
</template>

<script>
    import pricing from './pricing'
    import carddialog from './card-dialog'
    import {mapActions} from 'vuex'

    export default {
        name: "choosingplan",
        components: {
            pricing,carddialog
        },
        data() {
            return {
                selected: "",
                isCardDialogShow: false
            }
        },
        methods: {
            ...mapActions({
                sellerChoosingPlan: "$_Seller/SELLER_CHOOSING_PLAN",
                createCustomer: "$_Seller/CREATE_CUSTOMER",
            }),
            choosePlan(plan) {
                // this.isCardDialogShow = true
                // // alert(plan)
                this.selected = plan
                this.sellerChoosingPlan(plan).then(res => {
                    if (res.data.status) {
                        this.$router.push({name: 'AddShoptifyStore'})
                    } else {
                        this.isCardDialogShow = true
                    }
                })
            },
            createCardForCustomer(cardInfo) {
                let democart = {
                    "card_no": cardInfo.card_no.replace(/\W/gi, ''),
                    "ccExpiryMonth": cardInfo.expire_date.split('/')[0],
                    "ccExpiryYear": cardInfo.expire_date.split('/')[1],
                    "cvvNumber": cardInfo.secure_code,
                    "plan_id": this.selected
                }
                console.log(democart);
                this.isCardDialogShow = false
                this.createCustomer(democart).then(res => {
                    if (res.data.status) {
                        this.$router.push({name: 'AddShoptifyStore'})
                    } else {
                        this.isCardDialogShow = true
                        $notify({
                            content: res.data.message,
                            type: "danger"
                        })
                    }
                })
            }
        },
        created: function () {
            // load user info and current, dose add credit card
            // this.selected = 'free'
        }
    }
</script>

<style lang="scss" scoped>
    .plan-description {
        font-size: 35px;
    }

</style>
