<template>
    <div class="app-list-products" itemscope >
        <transition-group tag="div" class="row" name="page-container" mode="out-in">
            <template v-if="hasBanner">
                <template v-for="(item , index) in products">
                    <template v-if="index == 0">
                        <div class="col col-md-8 col-lg-6 m-b-30" itemprop="itemListElement" :key="`product_banner_0_${index}`" v-if="banners.length && banners[0]">
                            <div class="product-banner" >
                                <a href="#" >
                                    <img :src="banners[0].image" alt="">
                                </a>
                            </div>
                        </div>
                    </template>
                    <template v-if="index == 5">
                        <div class="col col-md-4 col-lg-3 m-b-30" itemprop="itemListElement" :key="`product_banner_1_${index}`" v-if="banners.length && banners[1]">
                            <div class="product-banner">
                                <a href="#" >
                                    <img :src="banners[1].image" alt="">
                                </a>
                            </div>
                        </div>
                    </template>
                    <div :class="col" :key="`product_index_${index}`" itemprop="itemListElement">
                        <product :product-info="item"></product>
                    </div>
                </template>
            </template>
            <template v-else>
                <template v-for="(item , index) in products">
                    <div :class="col" :key="`product_index_${index}`" itemprop="itemListElement">
                        <product :product-info="item"></product>
                    </div>
                </template>
            </template>
        </transition-group>
    </div>
</template>
<script>
import product from './product'
import { mapGetters } from 'vuex';
export default {
    name : 'ListProducts',
    components: {
        product
    },
    props:{
        products : {
            type : Array,
        },
        col :{
            type : String,
            default: 'col col-md-4 col-lg-3 m-b-30'
        },
        hasBanner:{
            type : Boolean,
            default : false
        }
    },
    data(){
        return{

        }
    },
    methods : {
        findIndex(index){
            var find = _.find(this.banners , { position : index })
            if( find ){
                return find
            }
            return null
        }
    },
    computed :{
        ...mapGetters({
            banners :   '$_Home/getBanners'
        })
    }
}
</script>
<style lang="scss" scoped>
    .product-banner{
        height: 100%;
        position: relative;
        a{
            display: block;
            height: 100%;
            position: relative;
            overflow: hidden;
            background-size: cover;
            background-position: center left;
            background-color: #fff;
            background-repeat: no-repeat;
            transition: all 0.3s ease;
            img{
                width: 100%;
                height: auto;
            }

            &:hover{
                background-position: center right;
            }
        }
    }
</style>
