<template>
    <div>
        <form  class="form-login" @submit.stop.prevent="submit" novalidate autocomplete="off">
            <div class="product-filter-title m-b-25">
                <span>{{ $t('auth.form.login.title') }}</span>
            </div>
            <p>{{ $t('auth.form.login.description') }}</p>
            <div class="form-group">
                <label class="input-title">{{ $t('auth.form.login.email') }} <span class="text-danger">*</span></label>
                <input class="form-control" type="email" v-model="form.email" :placeholder="$t('auth.form.login.email-placeholder')" :class="{'is-invalid': $v.form.email.$invalid && formstate}" />
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-10" v-if="$v.form.email.$invalid && formstate">
                        <p v-if="!$v.form.email.required"> {{ $t('auth.form.login.email-required') }} </p>
                        <p v-if="!$v.form.email.email"> {{ $t('auth.form.login.email-type') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group">
                <label class="input-title">{{ $t('auth.form.login.password') }} <span class="text-danger">*</span></label>
                <div class="form-control-password">
                    <input class="form-control" v-model="form.password" :type="hide_password_1 ? 'password' : 'text'" :placeholder="$t('auth.form.login.password-placeholder')" :class="{'is-invalid': $v.form.password.$invalid && formstate }" />
                    <span class="icon-show-password" @click.stop.prevent="hide_password_1 = !hide_password_1">
                        <i v-if="hide_password_1"  class="fas fa-eye"></i>
                        <i v-else class="fas fa-eye-slash"></i>
                    </span>
                </div>
                <transition name="fade" mode="out-in">
                    <div class="text-danger  m-t-10" v-if="$v.form.password.$invalid && formstate">
                        <p v-if="!$v.form.password.required"> {{ $t('auth.form.login.password-required') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group">
                <div class="row">
                    <div class="col col-6">
                        <div class="custom-checkbox">
                            <label><input type="checkbox" v-model="form.remember">{{ $t('auth.form.login.remember') }}</label>
                        </div>
                    </div>
                    <div class="col col-6 text-right">
                        <a href="#" @click.stop.prevent="changeMode()" class="text-yellow forgot-password"> {{ $t('auth.form.login.forgot-password') }} </a>
                    </div>
                </div>
            </div>
            <div class="form-group form-action">
                <transition name="fade" mode="out-in">
                    <div class="text-danger  m-t-10" v-if="error">
                        <p > {{ $t('auth.message.login-error') }} </p>
                    </div>
                </transition>
                <button class="save-login btn btn-warning btn-radius-border" type="submit" >
                    <transition name="fade" mode="out-in">
                        <span class="icon-loading small" v-if="isLoading" key="isloading"></span>
                    </transition>
                    {{ $t('auth.form.login.submit') }}
                </button>
            </div>
            <div class="social-network-container m-t-15">
                <loginFB :app-id="app_facebook_id" @login="fbLogin"></loginFB>
                <gglogin :app-id="app_google_id" @Login="ggLogin"></gglogin>
            </div>
        </form>
        <div class="modal fade" ref="modal_register" role="dialog">
            <div class="modal-dialog">
                <form @submit.stop.prevent="onRegisterWithSocial">
                    <div class="modal-content">
                        <div class="modal-title">
                            <div class="">Register</div>
                        </div>
                        <div v-if="!isSocialRegisterSuccess" class="modal-body">
                            <div class="register-fb-container">
                                <div class="row">
                                    <div class="form-group col col-12">
                                        <label class="input-title">email <span class="text-danger">*</span></label>
                                        <div class="outline-type">
                                            <input v-model="register.email" type="email" class="form-control" :disabled="isFbhaveEmail" :class="{'is-invalid': false}" placeholder="example@fireapps.com" />
                                        </div>
                                        <div class="invalid-feedback">
                                            <span>Email is invalid</span>
                                        </div>
                                    </div>
                                </div>
                                <div class="row">
                                    <div class="form-group col col-12">
                                        <label class="input-title">Password <span class="text-danger">*</span></label>
                                        <div class="form-control-password">
                                            <input :class="{'is-invalid': false}" :type="hide_password_2 ? 'password' : 'text'" v-model="register.password" class="form-control outline-type" placeholder="Password" />
                                            <span class="icon-show-password" @click.stop.prevent="hide_password_2 = !hide_password_2">
                                                <i v-if="hide_password_2"  class="fas fa-eye"></i>
                                                <i v-else class="fas fa-eye-slash"></i>
                                            </span>
                                        
                                        </div>
                                    </div>
                                    <div class="invalid-feedback">
                                        <span>Password length must more than 6</span>
                                    </div>
                                </div>
                                <div class="row">
                                    <div class="form-group col col-md-12">
                                        <label class="input-title">Country <span class="text-danger">*</span></label>
                                        <div class="outline-type select-outline">
                                            <select v-model="register.country_code" class="form-control">
                                                <option v-for="(item , index) in countries" :value="item.code" :key="`item${index}`">
                                                    {{item.name}}
                                                </option>
                                            </select>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div class="dialog-action m-b-15">
                                <button type="submit" class="btn btn-warning btn-radius-border m-t-25 text-white">
                                    <transition name="fade" mode="out-in">
                                        <span class="icon-loading small" v-if="register.isLoading" key="isloading"></span>
                                    </transition>
                                    {{ $t('auth.form.login.submit') }}
                                </button>
                            </div>
                        </div>
                        <div v-else class="modal-body">
                            <div class="register-fb-container">
                                <div class="sent-success">
                                    <p class="sent-success-title m-t-20 text-center">
                                        Check your email to continue
                                    </p>
                                    <button class="btn btn-default" type="button" data-dismiss>Close</button>
                                </div>
                            </div>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    </div>
</template>
<script>
import {required, minLength, email, sameAs} from 'vuelidate/lib/validators'
import {mapGetters, mapActions} from 'vuex';
import loginFB from './fblogin';
import gglogin from './gglogin';
import helper from '@/plugins/helper'
export default {
    name : 'Login',
    components:{
        loginFB, gglogin ,
    },
    props:{
        mode : {
            required : true,
            type : Boolean
        }
    },
    data(){
        return {
            form :{
                email : '',
                password : '',
                remember : false,
            },
            register: {
                email: '',
                password: '',
                country_code: 'US',
                id: '',
                name_social: '',
                isLoading : false,
                formstate : false,
            },
            formstate : false,
            show_password : false,
            isLoading : false,
            error : null,
            isSocialRegisterSuccess: false,
            isFbhaveEmail: true ,
            hide_password_1: true,
            hide_password_2: true
        }
    },
    computed:{
        ...mapGetters({
            app_facebook_id : 'getFacebookAppID',
            app_google_id : 'getGoogleAppID',
            countries : '$_Home/getCountries',
            router: 'getPreviousRouter'
        })
    },
    methods: {
        ...mapActions({
            sendLogin : "$_Seller/LOGIN",
            sendTokenToServer: "$_Seller/SEND_ACCESS_TOKEN",
            registerWithSocial: "$_Seller/REGISTER_WITH_SOCIAL",
            socialWithNewEmail: "$_Seller/SOCIAL_WITH_NEW_EMAIL",
        }),
        submit(){
            this.formstate = true 
            if( !this.$v.form.$invalid  && !this.isLoading ){
                this.isLoading = true
                this.sendLogin({
                    email: this.form.email,
                    password: this.form.password,
                    remember : this.form.remember
                }).then(res => {
                    this.isLoading = false
                    let {status, data , validate = null } = res.data 
                    if (status && validate) {
                        this.error = null
                        if (this.router && this.router.name) {
                            this.redirect(this.router.fullPath)
                        }else {
                            this.redirect({
                                name: 'Seller'
                            })
                        }
                    } else {
                        this.error = true
                    }
                }, error =>{
                    this.isLoading = false
                    this.error = true
                })
            }
        },
        changeMode(){
            this.$emit('update:mode' ,  false )
        },
        fbLogin(userInfo) {
            if (userInfo.status == "connected") {
                let user = {
                    token: userInfo.authResponse.accessToken,
                    type: "facebook"
                }
                this.sendTokenToServer(user).then(res => {
                    let { status , data } = res.data 
                    if (status) {
                        if (!data.token) {
                            this.register.email = data.email
                            this.register.id = data.fb_id
                            this.register.name_social = 'FB'
                            $(this.$refs.modal_register).modal('show')
                        } else {
                            this.$store.commit('$_Seller/LOGIN_SUCCESS', {
                                token : data.token,
                                remember : false
                            })
                            this.redirect({
                                name: 'Seller'
                            })
                        }
                    } else {
                        this.register.id = data.fb_id
                        this.register.name_social = 'FB'
                        this.isFbhaveEmail = false
                        $(this.$refs.modal_register).modal('show')
                    }
                })
            }
        },
        ggLogin(userInfo) {
            if (!userInfo.error) {
                let user = {
                    token: userInfo.Zi.id_token,
                    type: "google"
                }
                this.sendTokenToServer(user).then(res => {
                    let { status , data } = res.data 
                    if ( status ) {
                        if( data.token ){
                            this.$store.commit('$_Seller/LOGIN_SUCCESS', {token : data.token})
                            this.redirect({
                                name: 'Seller'
                            })
                        }else{
                            this.register.email = data.email
                            this.register.id = data.gg_id
                            this.register.name_social = 'GG'
                            $(this.$refs.modal_register).modal('show')
                        }
                    }
                }, error =>{

                })
            }
        },
        onRegisterWithSocial() {
            this.register.formstate = true
            if ( !this.$v.register.$invalid && !this.register.isLoading ) {
                if (this.isFbhaveEmail) {
                    this.register.isLoading = true
                    this.registerWithSocial(this.register).then(res => {
                        this.register.isLoading = false
                        let { status , data } = res.data 
                        if (status) {
                            this.$store.commit('$_Seller/LOGIN_SUCCESS', {
                                token : data.token,
                                remember  : false ,
                            })
                            this.redirect({
                                name: 'Seller'
                            })
                            $(this.$refs.modal_register).modal('hide')
                        } else {
                            $notify({
                                content: data.message,
                                type: "danger"
                            })
                        }
                    },error=>{
                        this.register.isLoading = false
                    })
                } else {
                    this.socialWithNewEmail(this.register).then(res => {
                        this.register.isLoading = false
                        let { status , data } = res.data 
                        if (status) {
                            this.isSocialRegisterSuccess = true
                        } else {
                            $notify({
                                content: "The email has already been taken",
                                type: "danger"
                            })
                        }
                    },error=>{
                        this.register.isLoading = false
                    })
                }
            }
        },
    },
    watch :{
        'form' : {
            handler : function(value){
                if( this.error ){
                    this.error = null
                }
            },
            deep : true
        }
    },
    validations(){
        return {
            form : {
                email : { required , email },
                password : { required }
            },
            register : {
                email : { required , email },
                password : { required },
                country_code : { required },
            }
        }
    }
}
</script>
<style lang="scss">
.form-login{
    .social-network-container{
        button{
            display: inline-block;
            vertical-align: middle;
            margin-left: 5px;
            border: none;
        }
    }
}
    
</style>
