<template>
    <div>
        <form @submit.stop.prevent="submit()" novalidate autocomplete="off">
            <div class="product-filter-title m-b-25">
                <span>Register</span>
            </div>
            <p>Start making business with us!</p>
            <div class="form-group become-input">
                <label class="input-title">Email <span class="text-danger">*</span> </label>
                <input class="form-control outline-type" type="email" v-model="form.email" :class="{ 'is-invalid' : $v.form.email.$invalid && formstate}" :placeholder="$t('auth.form.register.email-placeholder')"/>
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-5" v-if="$v.form.email.$invalid && formstate">
                        <p v-if="!$v.form.email.required"> {{ $t('auth.form.register.email-required') }} </p>
                        <p v-if="!$v.form.email.email"> {{ $t('auth.form.register.email-type') }} </p>
                        <p v-if="!$v.form.email.exist"> {{ $t('auth.form.register.email-exist') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group become-input">
                <label class="input-title">Password <span class="text-danger">*</span></label>
                <div class="form-control-password">
                    <input class="form-control outline-type" :type="hide_password_1 ? 'password' : 'text'" v-model="form.password" :class="{ 'is-invalid' : $v.form.password.$invalid && formstate}" :placeholder="$t('auth.form.register.password-placeholder')" />
                    <span class="icon-show-password" @click.stop.prevent="hide_password_1 = !hide_password_1">
                        <i v-if="hide_password_1"  class="fas fa-eye"></i>
                        <i v-else class="fas fa-eye-slash"></i>
                    </span>
                </div>
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-5" v-if="$v.form.password.$invalid && formstate">
                        <p v-if="!$v.form.password.required"> {{ $t('auth.form.register.password-required') }} </p>
                        <p v-if="!$v.form.password.minLength"> {{ $t('auth.form.register.password-min-length') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group become-input">
                <label class="input-title">Repassword <span class="text-danger">*</span></label>
                    <div class="form-control-password">
                    <input class="form-control outline-type" :type="hide_password_2 ? 'password' : 'text'" v-model="form.repassword" :class="{ 'is-invalid' : $v.form.repassword.$invalid && formstate}" :placeholder="$t('auth.form.register.password-placeholder')"/>
                    <span class="icon-show-password" @click.stop.prevent="hide_password_2 = !hide_password_2">
                        <i v-if="hide_password_2"  class="fas fa-eye"></i>
                        <i v-else class="fas fa-eye-slash"></i>
                    </span>
                </div>
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-5" v-if="$v.form.repassword.$invalid && formstate">
                        <p v-if="!$v.form.repassword.required"> {{ $t('auth.form.register.repassword-required') }} </p>
                        <p v-if="!$v.form.repassword.sameAs"> {{ $t('auth.form.register.repassword-same-as') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group become-input">
                <label class="input-title">Country <span class="text-danger">*</span></label>
                <div class="outline-type select-outline" :class="{ 'is-invalid' : $v.form.country_code.$invalid && formstate}">
                    <select class="form-control" v-model="form.country_code"  >
                        <option v-for="(item , index) in countries" :value="item.code" :key="`item${index}`">
                            {{item.name}}
                        </option>
                    </select>
                </div>
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-5" v-if="$v.form.country_code.$invalid && formstate">
                        <p v-if="!$v.form.country_code.required"> {{ $t('auth.form.register.country-code-required') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group become-input">
                <div class="accept-checkbox form-check form-check-inline m-t-5">
                    <div class="custom-checkbox">
                        <input class="form-check-input" type="checkbox" id="register-agree-checkbox" v-model="form.agree">
                    </div>
                    <label class="form-check-label" for="register-agree-checkbox"> {{ $t('auth.form.register.agree') }} <a href="" class="text-yellow"> {{ $t('auth.form.register.policy') }} </a></label>
                </div>
                <transition name="fade" mode="out-in">
                    <div class="text-danger m-t-5" v-if="$v.form.agree.$invalid && formstate">
                        <p v-if="!$v.form.agree.required"> {{ $t('auth.form.register.agree-required') }} </p>
                    </div>
                </transition>
            </div>
            <div class="form-group">
                <transition name="fade" mode="out-in">
                    <div class="text-danger" v-if="error">
                        {{ error }}
                    </div>
                </transition>
                
            </div>
            <div class="form-action m-t-20">
                <button class="save-login btn btn-warning btn-radius-border" type="submit">
                    <transition name="fade" mode="out-in">
                        <span class="icon-loading small" v-if="isLoading" key="isloading"></span>
                    </transition>
                    {{ $t('auth.form.register.submit') }} 
                </button>
            </div>
        </form>
    </div>
</template>
<script>
import {required, minLength, email, sameAs} from 'vuelidate/lib/validators'
import { mapGetters, mapActions } from 'vuex';
export default {
    name : 'Register',
    data(){
        return {
            form :{
                email : '',
                password : '',
                repassword : '',
                country_code : '',
                agree: false
            },
            formstate : false,
            isLoading : false,
            error : null,
            emails : [],
            hide_password_1 : true,
            hide_password_2 : true,
        }
    },
    computed:{
        ...mapGetters({
            countries : '$_Home/getCountries'
        })
    },
    methods:{
        ...mapActions({
            register : '$_Seller/REGISTER'
        }),
        submit(){
            this.formstate = true
            if (!this.$v.form.$invalid && !this.isLoading) {
                this.isLoading = true
                this.register({
                    email: this.form.email,
                    password: this.form.password,
                    country_code: this.form.country_code
                }).then(res => {
                    this.isLoading = false
                    let {status, data} = res.data
                    if (status) {
                        this.redirect({
                            name: 'SellerPlan'
                        })
                    } else {
                        if( typeof data.message == 'object'){
                            if( data.message.hasOwnProperty('email')){
                                this.emails.push(this.form.email)
                            }else{
                                this.error = data.message.email ? data.message.email[0] : 'error'
                            }
                        }else{
                            this.error = data.message
                        }
                    }
                }, error =>{
                    this.isLoading = false
                })
            }
        }
    },
    validations(){
        return {
            form :{
                email : { 
                    required , email ,
                    exist: function(value){
                        return this.emails.indexOf( value ) == -1
                    }
                },
                password: {
                    required, 
                    minLength: minLength(6)
                },
                repassword: {
                    required,
                    sameAs: sameAs('password')
                },
                country_code: {
                    required
                },
                agree: {
                    required: function (value) {
                        return value == true
                    }
                }
            }
        }
    }
}
</script>
