<template>
    <div class="become-supplier-container">
        <template v-if="!become_form_success">
            <div class="become-suppler-form">
                <div class="row">
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Company Name*</label>
                        <input class="form-control outline-type" :class="{
                        'is-invalid': !become_supplier_validate.shop_name,
                    }" v-model="become_supplier_form.shop_name"/>
                        <div class="invalid-feedback">
                            <span>Company Name is required</span>
                        </div>
                    </div>
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Website URL*</label>
                        <input class="form-control outline-type" :class="{
                        'is-invalid': !become_supplier_validate.website,
                    }" v-model="become_supplier_form.website"/>
                        <div class="invalid-feedback">
                            <span>Website is invalid</span>
                        </div>
                    </div>
                </div>
                <div class="row">
                    <div class="form-group become-input col col-4">
                        <label class="input-title">First name</label>
                        <input class="form-control outline-type" v-model="become_supplier_form.first_name"/>
                    </div>
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Last name</label>
                        <input class="form-control outline-type" v-model="become_supplier_form.last_name"/>
                    </div>
                </div>
                <div class="row">
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Job title</label>
                        <input class="form-control outline-type" v-model="become_supplier_form.job_title"/>
                    </div>
                    <div class="form-group become-input col col-md-4">
                        <label class="input-title">Country*</label>
                        <div class="outline-type select-outline">
                            <select class="form-control" v-model="become_supplier_form.country">
                                <option v-for="(item , index) in countries" :value="item.code" :key="`item${index}`">
                                    {{item.name}}
                                </option>
                            </select>
                        </div>
                    </div>
                </div>
                <div class="row">
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Phone number*</label>
                        <input class="form-control outline-type" :class="{
                        'is-invalid': !become_supplier_validate.phone_number,
                    }" v-model="become_supplier_form.phone_number"/>
                        <div class="invalid-feedback">
                            <span>Phone number is required</span>
                        </div>
                    </div>
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Warehouse location*</label>
                        <input class="form-control outline-type" :class="{
                        'is-invalid': !become_supplier_validate.warehouse_location,
                    }" v-model="become_supplier_form.warehouse_location"/>
                        <div class="invalid-feedback">
                            <span>Warehouse location is required</span>
                        </div>
                    </div>
                </div>
                <div class="row">
                    <div class="form-group become-input col col-4">
                        <label class="input-title">Email*</label>
                        <input class="form-control outline-type" :class="{
                        'is-invalid': !become_supplier_validate.email,
                    }" v-model="become_supplier_form.email"/>
                        <div class="invalid-feedback">
                            <span>{{emailError}}</span>
                        </div>
                    </div>
                </div>
                <div class="row">
                    <div class="accept-checkbox form-check form-check-inline">
                        <input v-model="isAcceptCondition" class="form-check-input" type="checkbox">
                        <label class="form-check-label">I have read and accept <a href="">the terms and
                            conditions</a></label>
                    </div>
                </div>
            </div>
            <div class="become-supplier-action m-t-30">
                <button :disabled="!isAcceptCondition" @click="become_supplier_validator"
                        class="save-become-supplier btn btn-warning btn-radius-border">
                    Resigter Now
                </button>
                <p class="m-t-15">
                    Already a supplier? <a href="" class="text-yellow">Go to supplier center</a>
                </p>
            </div>
        </template>
        <template v-else>
            <div class="success-container">
                <p class="thanks-ss">Thank you choosing Dropsquare</p>
                <div class="thanks-desscription">
                    We will check your infomation and get back to you as soon as posible.
                    For further infomation, please contact us at <span class="text-yellow">support@fireapps.io</span>
                </div>
                <div>
                    <!--<button class="btn btn-radius-border btn-warning text-white m-t-20">-->
                    <router-link :to="{name : 'Seller'}"
                                 class="text-white btn btn-radius-border btn-warning text-white m-t-20">Back to homepage
                    </router-link>
                    <!--</button>-->
                </div>
            </div>
        </template>
    </div>
</template>

<script>
    import {mapGetters, mapActions} from 'vuex';
    import helper from '@/plugins/helper'

    export default {
        name: "become-supplier",
        data() {
            return {
                become_supplier_form: {
                    country: "US",
                    shop_name: "",
                    website: "",
                    first_name: "",
                    last_name: "",
                    job_title: "",
                    phone_number: "",
                    warehouse_location: "",
                    email: "",
                },
                become_supplier_validate: {
                    country: true,
                    shop_name: true,
                    website: true,
                    phone_number: true,
                    warehouse_location: true,
                    email: true,
                },
                emailError: 'Email is invalid',
                isAllValidate: false,
                isAcceptCondition: false,
                become_form_success: false
            }
        },
        methods: {
            ...mapActions({
                become_supplier: "$_Seller/BECOME_SUPPLIER"
            }),
            become_supplier_validator: function () {
                this.become_supplier_validate.country = !!this.become_supplier_form.country
                this.become_supplier_validate.shop_name = !!this.become_supplier_form.shop_name
                this.become_supplier_validate.website = helper.validatewebsite(this.become_supplier_form.website)
                this.become_supplier_validate.phone_number = !!this.become_supplier_form.phone_number
                this.become_supplier_validate.warehouse_location = !!this.become_supplier_form.warehouse_location
                this.become_supplier_validate.email = helper.validateEmail(this.become_supplier_form.email)
                console.log(this.become_supplier_form);
                let isValidate = true;
                for (let key in this.become_supplier_validate) {
                    if (!this.become_supplier_validate[key]) {
                        if (key == 'email') {
                            this.emailError = 'Email is invalid'
                        }
                        isValidate = false
                    }
                }
                if (isValidate) {
                    this.become_supplier(this.become_supplier_form).then(res => {
                        console.log(res);
                        if (res.data.status) {
                            this.become_form_success = true
                        } else {
                            for (let key in res.data.data.message) {
                                let message = res.data.data.message[key][0]
                                // email validate
                                if (key == 'email') {
                                    this.emailError = message
                                    this.become_supplier_validate.email = false
                                }
                                //
                                $notify({
                                    content: message,
                                    type: 'danger'
                                })
                            }
                        }
                    })
                }
            }

        },
        computed: {
            ...mapGetters({
                countries: '$_Home/getCountries'
            })
        },
        watch: {
            'become_supplier_validate':{
                handler(val){
                    for (let key in val) {

                    }
                },
                deep: true
            }
        }
    }
</script>


<style lang="scss" scoped>
    @import 'src/assets/style';

    .become-suppler-form {
        .become-input {
            margin-top: 20px;
            input.form-control, .select-outline {
                height: 45px;
            }
        }
        .accept-checkbox {
            margin-left: 10px;
            a {
                color: $yellow;
            }
        }
    }

    .become-supplier-action {
        .save-become-supplier {
            color: white;
            padding-left: 20px;
            padding-right: 20px;

        }
    }

    .text-yellow {
        color: $yellow;
    }

    .success-container {
        text-align: center;
        .thanks-ss {
            font-size: 30px;
        }
        .thanks-desscription {
            font-size: 22px;
            max-width: 700px;
            margin: auto;
        }
    }
</style>
