<template>
    <div class="product-filter-tab-container">
        <ul class="nav filter-button-container">
            <li class="nav-item" >
                <router-link  class="btn btn-radius-border" :to="setRouterLink( { name : 'sort' , value : 'last'})" :class="{ 'active' : activeRouterLink('last') }">
                    Last
                </router-link>
            </li>
            <li class="nav-item" >
                <router-link  class="btn btn-radius-border" :to="setRouterLink( { name : 'sort' , value : 'trending'})" :class="{ 'active' : activeRouterLink('trending') }">
                    Trending
                </router-link>
            </li>
            <li class="nav-item" >
                <router-link  class="btn btn-radius-border" :to="setRouterLink( { name : 'sort' , value : 'price'})" :class="{ 'active' : activeRouterLink('price') }">
                    Price
                </router-link>
            </li>
            <li class="nav-item nav-item-special" v-if="$route.name != 'Premiums'">
                <router-link  class="btn btn-radius-border" :to="{ name : 'Premiums'}"  target="_blank">
                    <i class="fas fa-star"></i>Premium
                </router-link>
            </li>
        </ul>
    </div>
</template>
<script>
export default {
    name : 'TabFilterRouterLink',
    methods:{
        setRouterLink({name , value}){
            var query = JSON.parse(JSON.stringify(this.$route.query))
            query[name] = value
            return this.setRouterLinkDefault( {query : query} )
        },
        activeRouterLink(sort){
            return this.$route.query.sort == sort || this.$route.query.sort == undefined && sort =='last' 
        },
    }
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .product-filter-tab-container {
        margin-bottom: 30px;
        width: 100%;
        display: flex;
        .filter-button-container {
            flex: 1;
            text-align: right;
            display: block;
            .nav-item {
                display: inline-flex;
                margin-left: 2px;
                margin-right: 2px;
                &.nav-item-special{
                    a{
                        color:$yellow;
                        &.active{
                            background: $yellow;
                            color:#fff;
                        }
                    }
                }
            }
            span , a{
                color: $black;
                text-transform: capitalize;
                cursor: pointer;
                min-width: 90px;
                // padding: 6px 15px;
                &:focus{
                    box-shadow: 0 0 0 0.2rem rgba(255, 176, 17 , 0.25);
                }
                &.active {
                    border: 1px solid $yellow;
                }
            }
        }
    }
</style>
