<template>
	<div class="app-landing">
        <div class="app-landing-container container">
            <div class="app-landing-row row">
                <div class="app-landing-col app-landing-col-sidebar col">
                    <app-sidebar></app-sidebar>
                </div>
                <div class="app-landing-col app-landing-col-content col">
                    <tab-filter-router></tab-filter-router>
                    <transition name="fade-transform" mode="out-in">
                        <div class="row" v-if="isLoading" key="list-product-loading">
                            <div class="col col-12">
                                <product-loading :limit="12" col="col col-3 m-b-30"></product-loading>
                            </div>
                        </div>
                        <div  v-else key="row list-product-ready">
                            <template v-if="products.length">
                                <list-products :products="products" col="col col-md-4 col-lg-3 m-b-30" :has-banner="true"></list-products>
                                <div class="text-center">
                                    <button class="btn btn-light readmore">
                                        view more products
                                    </button>
                                </div>
                            </template>
                            <template v-else>
                                <div class="col col-12 ">
                                    <product-empty>
                                        <p>Sorry, we couldn't find any content </p>
                                    </product-empty>
                                </div>
                            </template>
                        </div>
                    </transition>
                </div>
                <template v-if="!isLoading">
                    <div class="app-landing-col app-landing-col-list col col-12 m-t-20" v-if="isLoggedIn" >
                        <list-product-filter title="Your Categories" mode="tab" :limit="10" :tab="top_category" col="col col-20 m-b-20" ></list-product-filter>
                    </div>
                    <div class="app-landing-col app-landing-col-list col col-12 m-t-20" >
                        <list-product-filter title="Recent Viewed Product" mode="recent" :limit="5"  col="col col-20 m-b-20" ></list-product-filter>
                    </div>
                </template>

            </div>
        </div>
    </div>

</template>

<script>
    import ListProducts from '../partials/list-products'
    import ProductEmpty from '../partials/product-empty'
    import ProductLoading from '../partials/product-loading'
    import AppSidebar from '../partials/sidebar'
    import TabFilterRouter from '../partials/tab-filter-router'
    import ListProductFilter from '../partials/list-product-filter'
    import helper from '@/plugins/helper'
    import { mapGetters, mapActions } from 'vuex';
	export default{
        name : 'Landing',
        components: {
            AppSidebar , TabFilterRouter , ListProducts , ProductEmpty , ProductLoading , ListProductFilter
        },
        metaInfo() {
            return {
                title: this.meta.title,
            }
        },
        data(){
            return {
                isLoading: false,
                sortables : ['last' ,'trending' ,'price'],
                products : [],
                default_sort : 'last',
                meta:{
                    title : 'All Collections'
                },
                pagination:{
                    current_page:  1,
                    sort : 'last',
                    shipping_from : '',
                    shipping_to : '',
                },
                top_category : []
            }
        },
        computed: {
            ...mapGetters({
                collections : '$_Home/getCollections',
                countries : '$_Home/getCountries',
                suppliers : '$_Home/getSuppliers',
                isLoggedIn : '$_Seller/isLoggedIn',
            }),
        },
        methods: {
            ...mapActions({
                getTopCategory : '$_Home/GET_TOP_CATEGORY'
            }),
            getProduct(to = null){
                if( to == null){
                    to = this.$route
                }
                let sort = to.query.sort ? to.query.sort : null 
                sort = this.checkSort(sort) ? sort : this.default_sort
                /* get current_page */
                let page = to.query.page   ? to.query.page : 1
                if( page ) {
                    page = helper.isNumeric(page) ? page : 1
                }
                /* get supplier_id */
                let supplier_id = to.query.supplier_id  ? to.query.supplier_id : null 
                if( supplier_id ) {
                    supplier_id = this.checkSupplier(supplier_id) ? supplier_id : null
                }
                /* get shipping_from */
                let shipping_from = to.query.shipping_from ?  to.query.shipping_from : null
                if( shipping_from ){
                    shipping_from = this.checkCountry(shipping_from) ? shipping_from : null
                }
                /* get shipping_to */
                let shipping_to = to.query.shipping_to  ? to.query.shipping_to : null
                if( shipping_to ){
                    shipping_to = this.checkCountry(shipping_to) ? shipping_to : null
                }
                /* get prices */
                let prices = null
                let price = to.query.prices 
                if( price ){
                    var temp = price.split('-')
                    if( temp.length == 2){
                        var min = temp[0].trim()
                        var max = temp[1].trim()
                        if( helper.isNumeric(min) && helper.isNumeric(max) && parseInt(min) <= parseInt(max)){
                            prices = price
                        }
                    }
                }
                return new Promise((resolve , reject )=>{
                    this.$store.dispatch('$_Home/GET_LIST_PRODUCTS' , { 
                        sort : sort,
                        page : page,
                        supplier_id: supplier_id,
                        shipping_from : shipping_from,
                        shipping_to : shipping_to,
                        prices : prices,
                        limit : 13,
                    }).then(res=>{
                        let { status , data , is_more } = res
                        if( status ){
                            this.products = data
                        }
                    })
                    resolve()
                })
            },
            checkCountry(code){
                return  _.find(this.countries , { code : code}) != undefined
            },
            checkSupplier(id){
                return _.find(this.suppliers , { id : id}) != undefined
            },
            checkSort(sort){
                return this.sortables.indexOf(sort) >= 0 
            }
        },
        beforeRouteUpdate : async function(to, from, next) {
            this.isLoading = true
            await this.getProduct(to)
            this.isLoading = false
            next()
        },
        created : async function(){
            this.isLoading = true
            this.$store.commit('$_Home/UPDATE_SIDEBAR_OPTION' , { collection_id : '' , more : false})
            await this.getProduct(this.$route)
            if( this.isLoggedIn ){
                var topCategory = await this.getTopCategory()
                if( topCategory ){
                    let { status , data } = topCategory
                    if( status ){
                        data.forEach((id)=>{
                            var item = helper.findDeep(this.collections , 'id' , (key , item) => item == id)
                            if( item && this.top_category.length <= 2){
                                this.top_category.push(item)
                            }
                        })
                    }
                }
            }
            
            this.isLoading = false
        }
	}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-landing{
        padding: 30px 0;
        &-container{

        }
        &-row{

        }
        &-col{
            &-sidebar{
                max-width: 20%;
            }
            &-content{
                max-width: 80%;
            }
        }
    }
</style>