import helper from '@/plugins/helper'
export default { 
    data(){
        return{
            activeSlide : 0,
            carousel :{
                perPage: 5,
                navigationEnabled: true,
                paginationEnabled: false,
                navigationPrevLabel : '<i class="fal fa-angle-left"></i>',
                navigationNextLabel: '<i class="fal fa-angle-right"></i>',
            },
            form : {
                properties : [],
                option : {}
            }
        }
    },
    methods:{
        onClickSlide(dataset){
            this.activeSlide = parseInt(dataset.index)
        },
        selectOption(option , value, image){
            if( this.form.option.hasOwnProperty(option) ){
                this.$set(this.form.option , option , value)
            }
            if( image && image.id){
                var index = _.findIndex( this.data.images , { id : image.id})
                if( index >= 0){
                    this.activeSlide = index;
                }
            }
        },
        activeOption({option , value}){
            return this.form.option[option] == value 
        },
        initDataProduct(product){
            var properties = []
            if( this.data ){
                var listWarehouses = this.data.warehouses
                var warehouses= []
                for (let i = 1; i <= 3; i++) {
                    var option_name = `option${i}`
                    if( this.data[option_name] ){
                        var option =[]
                        this.data.variants.forEach((item)=>{
                            if( item[option_name] ){
                                var img = '';
                                if( option_name == 'option1'){
                                    if( item.product_image_id  ){
                                        img = _.find(this.data.images , { id : item.product_image_id})
                                    }
                                    if( item.warehouse_id ){
                                        var find = _.find(warehouses , { id : item.warehouse_id})
                                        if( find == undefined){
                                            var warehouse = _.find(listWarehouses ,  { id : item.warehouse_id} )
                                            warehouses.push({
                                                id : item.warehouse_id,
                                                name : warehouse.country_name,
                                            })
                                        }
                                    }
                                }
                                var find = _.find(option , { name : item[option_name]})
                                if(  find == undefined){
                                    option.push({
                                        id : item[option_name],
                                        name : item[option_name],
                                        image : img,
                                    })
                                }
                                
                            }
                        })
                        if( option.length ){
                            properties.push({
                                id : option_name,
                                name : this.data[option_name],
                                data : option
                            })
                            this.$set(this.form.option , option_name , '')
                        }
                    }
                }
                properties.push({
                    id : 'warehouse_id',
                    name : 'warehouse',
                    data : warehouses
                })
                this.$set(this.form.option , 'warehouse_id' , '')
            }
            this.form.properties = properties;
        },
    },
    computed:{
        activeImage(){
            var src = null 
            if( this.data ){
                if( this.data.images.length &&  this.data.images.length >= this.activeSlide ){
                    src = this.data.images[this.activeSlide].src
                }
            }
            return src
        },
        selectedProduct(){
            var price = '' , is_selected = false , inventory = null
            if( this.data ){
                var is_select = true
                for (const key in this.form.option) {
                    if (this.form.option.hasOwnProperty(key)) {
                        if( this.form.option[key] == ''){
                            is_select = false
                            break
                        }
                    }
                }
                if( !is_select ){
                    if( this.data.price_min == this.data.price_max) {
                        price = `${helper.numberFormat(this.data.price_max)}$`
                    }else{
                        price = `${helper.numberFormat(this.data.price_min)}$ - ${helper.numberFormat(this.data.price_max)}$`
                    }
                }else{
                    var is_find = null;
                    this.data.variants.forEach(item=>{
                        if( is_find == null){
                            var is_valid = true
                            for (const key in this.form.option) {
                                if (this.form.option.hasOwnProperty(key)) {
                                    if( this.form.option[key] != item[key]){
                                        is_valid = false
                                        break
                                    }
                                }
                            }
                            if( is_valid ){
                                is_find = item
                            }
                        }
                    })
                    if( is_find ){
                        var num =  helper.isInterger(is_find.price) ? parseInt(is_find.price) : is_find.price 
                        price = `${helper.numberFormat(num)}$`
                        is_selected = true
                        inventory = is_find.inventory
                    }
                }
            }
            return {
                price : price,
                is_selected : is_selected ,
                inventory : inventory
            }
        }
    },
    watch :{
        data : function(value){
            if( value ){
                this.initDataProduct(value)
            }
        }
    },
}