<template>
    <div class="app-sidebar">
        <div class="app-sidebar-content" v-if="!isLoading">
            <!-- Box Collections -->
            <div class="app-sidebar-box" v-if="router.name != 'Collection'">
                <div class="sidebar-title">
                    <strong>All Categories</strong>
                </div>
                <div class="sidebar-collections" >
                    <ul class="collections">
                        <transition-group :css="false" @before-enter="fadeBeforeEnter" @enter="slideDownEnter" @leave="slideUpLeave" mode="out-in">
                            <template v-for="(item , index) in collections" >
                                <li  :key="`item${index}`" v-if="sidebar.more || index < 10">
                                    <div class="item">
                                        <router-link class="item-name" @click="reset()" :title="item.title" :to="setRouterLink(item)">
                                            {{item.title}}
                                        </router-link>
                                        <div class="item-toggle" :class="{'is-active' :  sidebar.collection_id == item.id}" v-if="item.childs.length" @click.stop.prevent="showCollection(item)">
                                            <i class="fal fa-angle-right"></i>
                                        </div>
                                    </div>
                                    <transition :css="false" @before-enter="fadeBeforeEnter" @enter="slideDownEnter" @leave="slideUpLeave" mode="out-in">
                                        <ul class="sub-collections" v-if="item.childs.length && sidebar.collection_id == item.id" >
                                            <li  v-for="(child , index_child) in item.childs" :key="`child${index_child}`">
                                                <div class="item">
                                                    <router-link class="item-name" @click="reset()"  :title="item.title" :to="setRouterLink(child)">
                                                        {{child.title}}
                                                    </router-link>
                                                </div>
                                            </li>
                                        </ul>
                                    </transition>
                                </li>
                            </template>
                        </transition-group>
                        <li v-if="collections.length >= 10">
                            <div class="item-readmore" @click="sidebar.more = !sidebar.more">
                                <button class="btn btn-light btn-sm">
                                    <template v-if="sidebar.more">
                                        Collapse
                                    </template>
                                    <template v-else>
                                        Expand
                                    </template>
                                </button>
                            </div>
                        </li>
                    </ul>
                </div>
            </div>
            <div class="app-sidebar-box" v-else>
                <template v-if="list">
                    <div class="sidebar-title" v-if="list.hasChild">
                        <template v-if="list.selected">
                            <strong>{{list.selected}}</strong>
                        </template>
                        <template v-else>
                            <strong> All categories</strong>
                        </template>
                    </div>
                    <div class="sidebar-collections" >
                        <ul class="collections">
                            <transition-group  name="fade" mode="out-in" >
                                <li v-for="(item , index) in list.list"  :key="`item${index}`" >
                                    <div class="item">
                                        <router-link class="item-name"  :title="item.title" :to="setRouterLink(item)">
                                            {{item.title}}
                                        </router-link>
                                        <div class="item-toggle" v-if="item.childs">
                                            <i class="fal fa-angle-right"></i>
                                        </div>
                                    </div>
                                </li>
                            </transition-group>
                        </ul>
                    </div>
                </template>
            </div>
            <!-- End Box Collections -->
            <!-- Box Supplier -->
            <div class="app-sidebar-box">
                <div class="sidebar-title">
                    <strong>Select supplier</strong>
                </div>
                <div class="sidebar-suppliers">
                    <div class="form-group-select">
                        <select  @change="onChangeHanler('supplier_id')"  class="form-control" v-model="option.supplier_id">
                            <option value="">All Suppliers</option>
                            <option v-for="(item , index) in suppliers" :key="index" :value="item.id">{{item.shop_name}}</option>
                        </select>
                    </div>
                </div>
            </div><!-- End Box Supplier -->
            <!-- Box Price -->
            <div class="app-sidebar-box">
                <div class="sidebar-title">
                    <strong>Price <small>(USD)</small></strong>
                </div>
                <div class="sidebar-price">
                    <div class="sidebar-price-content">
                        <div class="sidebar-price-input">
                            <money placeholder="From" :allow-blank="true"  v-model="option.min_price" v-bind="money" :min="0"  class="form-control" />
                        </div>
                        <div class="sidebar-price-input">
                            <money placeholder="To" :allow-blank="true" v-model="option.max_price" v-bind="money" :min="0"  class="form-control" />
                        </div>
                    </div>
                    <div class="sidebar-price-action">
                        <button class="btn btn-sm btn-warning" @click.stop.prevent="handleChangePrice()">Apply</button>
                    </div>
                </div>
            </div><!-- End Box Price -->
            <!-- Box Shipping -->
            <div class="app-sidebar-box">
                <div class="sidebar-title">
                    <strong>Shipping</strong>
                </div>
                <div class="sidebar-shipping">
                    <div class="sidebar-shipping-content">
                        <div class="sidebar-shipping-input">
                            <label for="sidebar_shipping_from">From</label>
                            <select @change="onChangeHanler('shipping_from')" v-model="option.shipping_from" id="sidebar_shipping_from">
                                <option value="">Select shipping</option>
                                <template v-for="(item , index)  in countries">
                                    <option v-if="item.code != option.shipping_to" :key="`shipping${index}`" :value="item.code">{{item.name}}</option>
                                </template>
                            </select>
                        </div>
                        <div class="sidebar-shipping-input">
                            <label for="sidebar_shipping_to">To</label>
                            <select @change="onChangeHanler('shipping_to')" v-model="option.shipping_to" id="sidebar_shipping_to">
                                <option value="">Select shipping</option>
                                <template v-for="(item , index)  in countries">
                                    <option v-if="item.code != option.shipping_from" :key="`shipping${index}`" :value="item.code">{{item.name}}</option>
                                </template>
                            </select>
                        </div>
                    </div>
                </div>
            </div><!-- End Box Shipping -->
            <div class="app-sidebar-box" v-if="banner">
                <div class="sidebar-images">
                    <a href="#">
                        <img :src="banner.image" alt="">
                    </a>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { mapGetters } from 'vuex'
import VueSlider from 'vue-slider-component'
import {Money} from '@/components/v-money'
import helper from '@/plugins/helper'
export default {
    name : 'SideBar',
    components:{
        VueSlider , Money
    },
    props:{
        list : {}
    },
    data(){
        return {
            child_collection : '',
            show_more : false,
            option : {
                supplier_id : '',
                min_price : 0,
                max_price : 0,
                shipping_from : '',
                shipping_to : ''
            },
            money: {
                decimal: ',',
                thousands: '.',
                prefix: '',
                suffix: ' $',
                precision: 0,
                masked: false 
            },
            isLoading: false
        }
    },
    computed:{
        sidebar:{
            get(){
                return this.$store.getters['$_Home/getSidebarOption']
            },
            set(value){
                this.$store.commit('$_Home/UPDATE_SIDEBAR_OPTION' , value)
            }
        },
        banner(){
            var banners = this.$store.getters['$_Home/getBanners']
            if( banners.length >= 3){
                return banners[2]
            }
            return null
        },
        ...mapGetters({
            collections : '$_Home/getCollections',
            suppliers : '$_Home/getSuppliers',
            countries : '$_Home/getCountries',
            router  : 'getRouter'
        }),
        
    },
    methods:{
        slideDownEnter(el, done){
            $(el).slideDown(600 ,function(){
                done();
            });
        },
        slideUpLeave(el, done){
            $(el).slideUp(600 ,function(){
                done();
            });
        },
        setRouterLink(item){
            var slug = helper.toSlug(item.title) + '-'+ item.id
            var query = {}
            if( this.$route.name == 'Collection'){
                query = JSON.parse( JSON.stringify(this.$route.query) )
                if( query.hasOwnProperty('page')){
                    delete query['page']
                }
            }
            var object =  {
                name : 'Collection',
                params :{
                    id : slug
                },
                query : query
            }
            return this.setRouterLinkDefault(object)
        },
        showCollection(item){
            this.sidebar.collection_id =  this.sidebar.collection_id == item.id ? '' : item.id
        },
        onChangeHanler(field){
            var value = this.option[field] 
            this.onChange({ key : field , value : value })
        },
        onChange({key , value}){
            var query = JSON.parse(JSON.stringify(this.$route.query))
            query[key] = value
            if( query.hasOwnProperty('page')){
                query['page'] = 1
            }
            this.pushRouterLinkDefault({name : this.$route.name , query : query})
        },
        handleChangePrice(){
            var query = JSON.parse(JSON.stringify(this.$route.query))
            query['prices'] = `${this.option.min_price}-${this.option.max_price}`
            if( query.hasOwnProperty('page')){
                query['page'] = 1
            }
            this.pushRouterLinkDefault({name : this.$route.name , query : query})
        },
    },
    created : async function(){
        var shipping_from = this.$route.query.shipping_from  ? this.$route.query.shipping_from : ''
        if( shipping_from && shipping_from != ''){
            var find = _.find(this.countries , { code : shipping_from})
            if( find  == undefined ){
                shipping_from = ''
            }
        }
        var shipping_to = this.$route.query.shipping_to  ? this.$route.query.shipping_to : ''
        if( shipping_to && shipping_to != ''){
            var find = _.find(this.countries , { code : shipping_to})
            if( find  == undefined ){
                shipping_to = ''
            }
        }
        var supplier_id = this.$route.query.supplier_id ? this.$route.query.supplier_id : '' 
        if( supplier_id && supplier_id != ''){
            var find = _.find(this.suppliers , { id : supplier_id})
            if( find  == undefined ){
                supplier_id = ''
            }
        }
        this.option.shipping_from = shipping_from
        this.option.shipping_to = shipping_to
        this.option.supplier_id = supplier_id
        var price = this.$route.query.prices
        if( price ){
            var prices = price.split('-')
            if( prices.length == 2){
                var min = prices[0].trim()
                var max = prices[1].trim()
                if( helper.isNumeric(min) && helper.isNumeric(max) && parseInt(min) <= parseInt(max)){
                    this.option.min_price = parseInt(min)
                    this.option.max_price = parseInt(max)
                }
            }
        }
    },
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/scss/static/variables';
    
    $border-color:#707070;
    $collection-color : #6E6E6E;
    $collection-color-hover : $text-color;
    .app-sidebar{
        &-box{
            width: 100%;
            margin-bottom: 20px;
        }
        .sidebar{
            &-title{
                font-size: 16px;
                text-transform: uppercase;
                margin-bottom: 10px;
                padding: 6px 15px;
                &-item{
                    a.item-name{
                        color:$text-color;
                        opacity: 0.8;
                        &:hover{
                            color:$yellow;
                            text-decoration: underline;
                        }
                    }
                    .item-name{
                        color:$text-color;
                        opacity: 0.8;
                        font-size: 14px;
                    }
                }
            }
            &-collections{
                ul{
                    list-style-type: none;
                    padding: 0;
                    margin: 0;
                }
                .collections{
                    .item{
                        display: flex;
                        flex-direction: row;
                        flex-wrap: nowrap;
                        padding: 6px 6px 6px 15px;
                        line-height: 25px;
                        border: 1px solid transparent;
                        &:hover{
                            // background-color: #e2e6ea;
                            // border-color: #dae0e5;
                            // .item-name{
                            //     color:$yellow;
                            // }
                        }
                        &-name{
                            flex: auto;
                            cursor: pointer;
                            color:$collection-color;
                            white-space: nowrap;
                            overflow: hidden;
                            text-overflow: ellipsis;
                            text-decoration: none;
                            &.router-link-exact-active.router-link-active{
                                color:$collection-color-hover;
                                font-weight: bold;
                            }
                            &:hover{
                                color:$collection-color-hover;
                            }
                        }
                        &-toggle{
                            width: 25px;
                            height: 25px;
                            display: inline-flex;
                            justify-content: center;
                            align-items: center;
                            text-align: center;
                            cursor: pointer;
                            border-radius: 5px;
                            transition: all 0.3s ease;
                            transform: none;
                            transform-origin: center center;
                            font-size: 20px;
                            &.is-active{
                                transform: rotate(90deg)
                            }
                            &:hover{
                                // background: #ccc;
                                color:$yellow;
                            }
                        }
                        
                    }
                    .item-readmore{
                        background-color: #e2e6ea;
                        border-color: #dae0e5;
                        button{
                            width: 100%;
                            display: block;
                        }
                        &:hover{
                            color:$yellow;
                        }
                    }
                    .sub-collections{
                        padding-left: 20px;
                    }
                }
            }
            &-suppliers{
                padding: 0 15px;
                .form-control{
                    border-radius: 24px;
                    border-color: $border-color;
                    font-size: 13px;
                }
            }
            &-price{
                padding: 0 15px;
                &-slider{
                    margin-bottom: 10px;
                }
                &-content{
                    display: flex;
                    flex-direction: row;
                    flex-wrap: wrap;
                    margin-bottom: 15px;
                }
                &-action{
                    text-align: right;
                    button{
                        color:#fff;
                        background: $yellow;

                    }
                }
                &-input{
                    flex: 1 1;
                    max-width: 100px;
                    margin-left: 15px;
                    &:first-child{
                        margin-left: 0;
                    }
                    .form-control{
                        border-radius: 24px;
                        text-align: center;
                        border-color:$border-color;
                        font-size: 13px;
                    }
                }
            }
            &-shipping{
                padding: 0 15px;
                &-content{

                }
                &-input{
                    display: flex;
                    flex-direction: row;
                    flex-wrap: nowrap;
                    border: 1px solid $border-color;
                    margin-bottom: 15px;
                    border-radius: 24px;
                    height: 38px;
                    padding: 6px 5px 6px 15px;
                    font-size: 1rem;
                    font-weight: 400;
                    line-height: 1.5;
                    color: #495057;
                    background-color: #fff;
                    background-clip: padding-box;
                    transition: border-color 0.15s ease-in-out, box-shadow 0.15s ease-in-out, -webkit-box-shadow 0.15s ease-in-out;
                    white-space: nowrap;
                    position: relative;
                    &:first-child{
                        margin-left: 0;
                    }
                    label{
                        width: 50px;
                        margin: 0;
                        color:#C5C5C5;
                    }
                    select{
                        width: calc(100% - 50px);
                        appearance: none;
                        border: none;
                        color:$text-color;
                        padding-right: 20px;
                        overflow: hidden;
                        text-overflow: ellipsis;
                        white-space: nowrap;
                        font-size: 13px;
                        &:focus{
                            outline: none;
                        }
                    }
                    &:after{
                        content:"\f107";
                        position:absolute;
                        z-index:2;
                        right: 10px;
                        top: 50%;
                        transform: translateY(-50%);
                        pointer-events:none;
                        @include fontawesome;
                        font-weight: 300;
                        color: #495057;
                        font-size: 20px;
                    }
                }
            }
            &-images{
                img{
                    max-width: 100%;
                }
            }
        }
    }
</style>
