import Vue from 'vue'
import App from './App.vue'
import router from './router'
import store from './store'
import './plugins'
import './modules'
import i18n from './lang'


Vue.config.productionTip = false

const app = new Vue({
	router,
	i18n,
	store,
	render: h => h(App)
}).$mount('#app')
export default app