<template>
    <div class="app-product-question">
        <div class="app-product-question-head">

        </div>
        <div class="app-product-question-body" >
            <transition name="fade-transform" mode="out-in">
                
                <div class="app-product-question-body-content" v-if="!isLoading"  key="is-loaded">
                    <div class="list-question" v-if="data.length">
                        <div class="item-question" v-for="(item, index) in data" :key="`index${index}`">
                            <div class="item-question-title">
                                {{item.title}}
                            </div>
                            <div class="item-question-created">
                                {{item.created_at | date_format}}
                            </div>
                        </div>
                    </div>
                    <div class="list-question" v-else>
                        <div class="item-empty">
                            Empty question
                        </div>
                    </div>
                    <div class="text-center">
                        <pagination :change="onChange" :router-link="false" v-model="pagination.current_page" :total="pagination.total_page"></pagination>
                    </div>
                </div>
                <div class="app-product-question-body-loading" v-else key="is-loading">
                    <div class="icon-loading"></div>
                </div>
            </transition>
        </div>
        <div class="app-product-question-foot" >
            <div class="app-product-question-foot-chat-box" v-if="isLoggedIn"  :class="{ 'is-disabled' : isLoading}">
                <textarea  ref="input" class="form-control" v-model.trim="content" @keypress.13.prevent="addQuestion"></textarea>
                <div class="text-right m-t-10">
                    <button class="btn btn-warning btn-send" @click.stop.prevent="addQuestion">
                        <i class="icon-loading" v-if="isPost"></i>
                        <template v-else>Send</template>
                    </button>
                </div>
            </div>
            <div class="app-product-question-foot-auth" v-else>
                <div class="text-center">
                    Please <router-link :to="{ name : 'Login'}"> Login </router-link> or <router-link :to="{ name : 'Login'}"> Register </router-link> to add question !
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { mapGetters } from 'vuex';

export default {
    name : 'ProductQuestion',
    props : {
        productId : {
            type : String, 
            required : true
        }
    },
    data(){
        return {
            pagination : {
                limit : 10,
                current_page : 1,
                total_page : 0,
            },
            content : '',
            data : [],
            isPost : false,
            isLoading : false
        }
    },
    computed :{
        ...mapGetters({
            isLoggedIn : '$_Seller/isLoggedIn'
        })
    },
    methods:{
        load(){
            if(  this.isLoading ) return
            this.isLoading = true
            this.$store.dispatch('$_Home/GET_PRODUCT_QUESTION' , { 
                id : this.productId,
                current_page : this.pagination.current_page ,
            }).then( res=>{
                this.isLoading  = false
                let { status , data , pagination } = res 
                if( status ){
                    this.data = data
                    this.pagination.current_page = pagination.current_page 
                    this.pagination.total_page = pagination.total_page 
                }
            })
        },
        addQuestion(){
            this.$refs.input.blur()
            if( this.content == '' ) return;
            this.isPost = true
            this.$store.dispatch('$_Home/POST_PRODUCT_QUESTION' , { id : this.productId , content : this.content}).then( res=>{
                let { status , data } = res 
                this.isPost = false
                if( status ){
                    this.content = ''
                    this.pagination.current_page = 1 
                    this.load()
                }
            })
        },
        onChange(page){
            this.pagination.current_page = page 
            this.load()
        }
    },
    created :  function(){
        this.load()
    }
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-product-question{
        &-head{

        }
        &-body{
            &-content{

            }
            &-loading{
                min-height: 300px;
                display: flex;
                justify-content: center;
                align-items: center;
                .icon-loading{
                    width: 50px;
                    height: 50px;
                    background: $yellow;
                }
            }
        }
        &-foot{
            &-chat-box{
                &.is-disabled{
                    opacity: 0.7;
                    pointer-events: none;
                }
                .form-control{
                    min-height: 100px;
                }
            }
            &-auth{
                padding: 30px 0;
                font-size: 16px;
                a{
                    font-weight: bold;
                    color:$yellow;
                    display: inline-block;
                    margin: 0 5px;
                    &:hover{
                        text-decoration: underline;
                    }
                }
            }
        }
        .list-question{
            .item-empty{
                padding: 10px 0 20px 0;
            }
            .item-question{
                margin-bottom: 10px;
                &-title{
                    font-size: 14px;
                    font-weight: bold;
                }
                &-created{
                    font-size: 12px;
                    font-weight: normal;
                    color:#888;
                }
            }
        }
        .chat-box{
            -webkit-user-select: text;
            -moz-user-select: text;
            -ms-user-select: text;
            user-select: text;
            text-shadow: 0px 0 0px rgba(0, 0, 0, 0.4);
            border:1px solid #ddd;
            background: #fff;
            box-sizing: border-box;
            min-height: 60px;
            max-height: 166px;
            justify-content: center;
            flex-direction: column;
            font-size: 15px;
            padding: 16px 10px 16px 19px;
            overflow: auto;
            flex: 1 1 auto;
            word-break: break-all;
            word-break: break-word;
            word-wrap: break-word;
            &:focus{
                box-shadow: 0 0 0 0.2rem rgba(0, 123, 255, 0.25);
                border-color: #80bdff;
                outline: none;
            }
            &.empty{
                &:before{
                    content: attr(placeholder);
                    cursor: text;
                    background: none;
                    color: #83878d;
                    display: block;
                    position: absolute;
                    padding-top: 5px;
                    left: 19px;
                    right: 150px;
                    text-overflow: ellipsis;
                    white-space: nowrap;
                    overflow: hidden;
                    pointer-events: none;
                }
            }
            
        }
        .btn-send{
            color:#fff;
            background: $yellow;
            min-width: 100px;
            display: inline-flex;
            justify-content: center;
            align-items: center;
            .icon-loading{
                height: 24px;
                width: 24px;
                background-color: #fff;
            }
            &:hover{
                color:#fff;
            }
            &:focus, &:visited{
                color:#fff;
            }
        }
    }
</style>

