<template>
    <div class="modal fade" id="credit-dialog" role="dialog">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-body">
                    <div class="shoptify-link-container">
                        <div class="row credit-card-form">
                            <div class="card-number form-group col col-12">
                                <label class="input-title">Card Number <span class="text-danger">*</span></label>
                                <div class="outline-type">
                                    <input :class="{'is-invalid': !cardInfoValidate.card_no}"
                                           class="form-control border-0" maxlength="19" v-on:keypress="isNumber()"
                                           v-model="cardInfo.card_no"
                                           placeholder="XXXX XXXX XXXX XXXX" type="text"/>
                                    <img v-if="cardInfo.card_type=='visa'" src="../../../assets/images/icons/visa.png"
                                         alt="">
                                    <img v-if="cardInfo.card_type=='master'"
                                         src="../../../assets/images/icons/master.png" alt="">
                                </div>
                            </div>
                            <!--<div class="form-group col col-12">-->
                            <!--<label class="input-title">Card Name<span class="text-danger">*</span></label>-->
                            <!--<input class="form-control outline-type" placeholder="Peter Nguyen" type="text"/>-->
                            <!--<div class="invalid-feedback">-->
                            <!--<span>Current password is require</span>-->
                            <!--</div>-->
                            <!--</div>-->
                        </div>
                        <div class="row credit-card-form secure-code">
                            <div class="form-group col col-4">
                                <label class="input-title">Expire Date<span class="text-danger">*</span></label>
                                <input :class="{'is-invalid': !cardInfoValidate.expire_date}"
                                       v-model="cardInfo.expire_date" class="form-control outline-type"
                                       maxlength="5"
                                       v-on:keypress="isNumber()"
                                       placeholder="MM/YY" type="text"/>
                            </div>
                            <div class="form-group col col-4">
                                <label class="input-title">Secure code<span class="text-danger">*</span></label>
                                <input :class="{'is-invalid': !cardInfoValidate.secure_code}"
                                       v-model="cardInfo.secure_code" class="form-control outline-type"
                                       maxlength="3"
                                       placeholder="567" type="password"/>
                            </div>
                        </div>
                    </div>
                    <div class="dialog-action">
                        <button class="btn btn-warning btn-radius-border m-t-25 text-white"
                                @click="createCardForCustomer">Confirm
                        </button>
                    </div>
                    <!--<div class="dialog-hepper m-t-25">-->
                    <!--<div>-->
                    <!--<a class="text-warning">-->
                    <!--Card info step ....-->
                    <!--</a>-->
                    <!--</div>-->
                    <!--</div>-->
                </div>
            </div>
        </div>
    </div>
</template>

<script>
    export default {
        name: "card-dialog",
        props: ["isShow"],
        data() {
            return {
                cardInfo: {
                    card_no: '',
                    secure_code: '',
                    expire_date: '',
                    card_type: ''
                },
                cardInfoValidate: {
                    card_no: true,
                    secure_code: true,
                    expire_date: true
                }
            }
        },
        created: function () {
            if (this.isShow) {
                $('#credit-dialog').modal('show')
            }
            $(document).on('hide.bs.modal', '#credit-dialog', () => {
                this.$emit('modalHide')
            });
        },
        methods: {
            checkCard(number) {
                let mastercard = /^5[1-5][0-9]{14}$/
                let visa = /^4[0-9]{12}(?:[0-9]{3})?$/
                if (visa.test(number)) {
                    this.cardInfo.card_type = 'visa'
                } else if (mastercard.test(number)) {
                    this.cardInfo.card_type = 'master'
                } else {
                    this.cardInfo.card_type = ''
                }
            },
            isNumber: function (evt) {
                evt = (evt) ? evt : window.event;
                var charCode = (evt.which) ? evt.which : evt.keyCode;
                if ((charCode > 31 && (charCode < 48 || charCode > 57)) && charCode !== 46) {
                    evt.preventDefault();
                } else {
                    return true;
                }
            },
            createCardForCustomer() {
                let card_no = this.cardInfo.card_no.replace(/\W/gi, '');
                let expire_date = this.cardInfo.expire_date.replace(/\W/gi, '');
                let secure_code = this.cardInfo.secure_code
                this.cardInfoValidate.card_no = card_no.length == 16
                this.cardInfoValidate.expire_date = expire_date.length == 4
                this.cardInfoValidate.secure_code = secure_code.length == 3
                let isValidate = true
                for (let key in this.cardInfoValidate) {
                    if (!this.cardInfoValidate[key]) {
                        isValidate = false
                    }
                }
                if (isValidate) {
                    this.$emit('dialogConfirm', this.cardInfo)
                    this.cardInfo = {
                        card_no: '',
                        secure_code: '',
                        expire_date: '',
                        card_type: ''
                    }
                }
            }
        },
        watch: {
            "isShow": function (value) {
                console.log(this.isShow);
                if (value) {
                    $('#credit-dialog').modal('show')
                } else {
                    $('#credit-dialog').modal('hide')
                }
            },
            "cardInfo.card_no": function (value) {
                let temp = value.replace(/\W/gi, '');
                for (let i = temp.length; i < 16; i++) {
                    temp += '1'
                }
                this.checkCard(temp);
                // 422149867705
                this.cardInfo.card_no = value.replace(/\W/gi, '').replace(/(.{4})/g, '$1 ');
            },
            "cardInfo.expire_date": function (value) {
                this.cardInfo.expire_date = value.replace(/\W/gi, '').replace(/^(.{2})/g, '$1/');
            }
        }
    }
</script>

<style lang="scss" scoped>
    .credit-card-form {
        &.secure-code {
            input {
                text-align: center;
            }
        }
        .card-number {
            img {
                position: absolute;
                right: 10px;
                top: 50%;
                transform: translateY(-50%);
                width: 40px;
            }
            div.outline-type {
                position: relative;
            }
        }
        .form-group {
            & > label {
                text-align: left;
                width: 100%;
            }
            input {
                letter-spacing: 3px;
                /*text-align: center;*/
            }
        }
    }

    .modal-body {
        padding: 30px;
    }

    .dialog-action {
        text-align: center;
        button {
            min-width: 120px;
        }
    }
</style>
