<template>
    <div  class="list-flags" >
        <template v-if="!loading">
            <template v-if="value.length > limit">
                <template v-for="(item , index) in value">
                    <div class="item-flag" :key="index" v-if="index < limit"  >
                        <div class="item-flag-container">
                            <span  :class="`flag-icon flag-icon-${item.code}`"></span>
                        </div>
                    </div>
                </template>
                <div class="item-flag item-flag-more" >
                    <div class="btn-show-more" @click="toggleShowMore()" >
                        {{ value.length - limit }} +
                    </div>
                    <transition name="fade">
                        <div class="show-more-dropdown" v-if="showmore" v-on-clickaway="clickOutSideShowMore">
                            <ul>
                                <template v-for="(item, index) in value" >
                                    <li v-if="index >= limit" :key="index">
                                        <div class="item-flag">
                                            <div class="item-flag-container">
                                                <span  :class="`flag-icon flag-icon-${item.code}`"></span>
                                            </div>
                                        </div>
                                        <span class="text">{{item.name}}</span>
                                    </li>
                                </template>
                            </ul>
                        </div>
                    </transition>
                </div>
            </template>
            <template v-else>
                <template v-for="(item , index) in value">
                    <div class="item-flag" :key="index" >
                        <div class="item-flag-container" >
                            <span  :class="`flag-icon flag-icon-${item.code}`"></span>
                        </div>
                    </div>
                </template>
            </template>
        </template>
    </div>
</template>
<script>
export default {
    name :  'ListFlags',
    props :{
        value : {
            type : Array,
            required: true,
        },
    },
    data(){
        return {
            showmore : false,
            limit : 3,
            loading  : true,
        }
    },
    mounted(){
        setTimeout( () => {
            var container = this.$el.offsetWidth - 40;
            var total = Math.floor(container / 39)
            this.limit = total 
            this.loading = false
        }, 50);
    },
    methods:{
        clickOutSideShowMore(){
            if( this.showmore ){
                this.showmore = false;
            }
        },
        toggleShowMore(){
            this.showmore = true;
        },
    }
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .list-flags{
        display: flex;
        flex-direction: row;
        flex-wrap: nowrap;

        .item-flag{
            &-container{
                position: relative;
                margin-right: 5px;
                &:hover{
                    .btn-remove-flag{
                        opacity: 1;
                        visibility: visible;
                    }
                }
            }
            .flag-icon{
                position: relative;
                cursor: pointer;
            }
            &.item-flag-more{
                
                position: relative;
                .btn-show-more{
                    width: 100%;
                    background: $purple;
                    color:#fff;
                    text-align: center;
                    border-radius: 3px;
                    font-size: 13px;
                    width: 34px;
                    height: 25.5px;
                    line-height: 25px;
                    user-select: none;
                    cursor: pointer;
                }
                .show-more-dropdown{
                    position: absolute;
                    left: 100%;
                    top: 0;
                    z-index: 10;
                    background: #fff;
                    box-shadow: 1px 3px 7px rgba(0, 0, 0, 0.2);
                    border-radius: 5px;
                    overflow: hidden;
                    max-height: 200px;
                    overflow: hidden auto;
                    padding: 10px ;
                    width:200px;
                    padding:10px;
                    border: 1px solid #eee;
                    ul{
                        list-style: none;
                        padding: 0;
                        margin: 0;
                        li{
                            margin-bottom: 5px;
                            .text{
                                line-height: 25px;
                                display: block;
                                float: left;
                                width: calc(100% - 40px);
                                overflow: hidden;
                                text-overflow: ellipsis;
                                white-space: nowrap;
                                padding-left: 10px;
                            }
                            span{
                                vertical-align: middle;
                            }
                            .item-flag{
                                margin: 0;
                                float: left;
                                padding: 0;
                                width: 34px;
                                height: 25.5px;
                                .flag-icon{
                                    width: 34px;
                                    height: 25.5px;
                                }
                            }
                            @include clearfix;
                            &:last-child{
                                margin-bottom: 0;
                            }
                        }
                    }
                }
            }
        }
    }
</style>
