<template>
    <div class="app-list-product-filter">
        <div class="app-list-product-filter-header" :class="{ 'is-mode-tab' : mode == 'tab'}">
            <div class="app-list-product-filter-title">
                <h3 >{{title}}</h3>
            </div>
            <div class="app-list-product-filter-tab" v-if="mode == 'tab'">
                <ul class="nav filter-button-container">
                    <li class="nav-item" v-for="(item , index) in tab" :key="`tab_${index}`" >
                        <button class="btn btn-radius-border" @click.stop.prevent="changeTab(index)" :class="{'active' : index == activeTab}">
                            {{item.title}}
                        </button>
                    </li>
                </ul>
            </div>
        </div>
        
        <transition name="fade" mode="out-in">
            <div class="app-list-product-filter-content" v-if="isLoading" key="is-loading">
                <product-loading :limit="limit" :col="col"></product-loading>
            </div>
            <div class="app-list-product-filter-content" v-else key="is-loaded">
                <div v-if="products.length">
                    <list-products :products="products" :col="col" ></list-products>
                </div>
                <div v-else>
                    empty product
                </div>
            </div>
        </transition>
    </div>
</template>
<script>
import ListProducts from './list-products'
import ProductLoading from './product-loading'
export default {
    name : 'ListProductFilter',
    props : {
        productId :{
            type :String
        },
        mode : {
            required : true,
            type : String
        },
        limit :{
            type : Number,
            default : 8
        },
        title : {
            type : String,
            default : ''
        },
        tab : {
            type : Array,
        },
        col : {
            type : String,
            default : 'col col-20 m-b-20'
        }
    },
    components: {
        ListProducts , ProductLoading
    },
    data(){
        return {
            isLoading : false,
            products : [],
            activeTab : 0,
        }
    },
    methods:{
        getFilter(){
            if( this.mode == 'tab' ){
                if(  this.tab.length  &&  this.tab.length >= this.activeTab ){
                    var index = this.activeTab
                    var filter = {
                        collection_id : this.tab[index].id,
                        limit : this.limit,
                    }
                    this.loadListProduct(filter)
                }
            }else if( this.mode == 'recent'){
                let ids = this.getLocalStore('lr')
                ids = ids == undefined ? [] : ids
                if (ids.length >= this.limit)  {
                    ids = _.takeRight(ids, 5)
                }
                if( ids.length ){
                    this.loadProductByIds(ids)
                }
            }
        },
        loadListProduct(filter){
            this.isLoading = true
            this.$store.dispatch('$_Home/GET_LIST_PRODUCTS' , filter).then( res=>{
                this.isLoading = false
                let { status , data } = res 
                if( status ){
                    this.products = data
                }
            })
        },
        loadProductByIds(ids){
            this.isLoading = true
            this.$store.dispatch('$_Home/GET_RECENT_PRODUCT' , ids).then( res=>{
                this.isLoading = false
                let { status , data } = res.data
                if( status ){
                    this.products = data
                }
            })
        },
        changeTab(index){
            if( this.activeTab != index){
                this.activeTab = index
                this.getFilter()
            }
        }
    },
    mounted(){
        this.getFilter()
    }
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-list-product-filter{
        &-header{
            display: flex;
            flex-direction: row;
            flex-basis: nowrap;
            margin-bottom: 20px;
            height: 45px;
            border-bottom:1px solid #eee;
        }
        &-title{
            flex: 1 1 ;
            position: relative;
            h3, h4{
                line-height: 45px;
                margin: 0;
                font-size: 18px;
                text-transform: capitalize;
                color:$text-color;
                line-height: 45px;
                position: relative;
                display: inline-block;
                &:before{
                    content : '';
                    height: 3px;
                    width: calc(100% + 30px);
                    position: absolute;
                    bottom: -1px;
                    left: 0;
                    background: $yellow;
                }
            }
        }
        &-tab{
            flex : 1 1;
        }
        .filter-button-container{
            flex: 1;
            text-align: right;
            display: block;
            .nav-item {
                display: inline-flex;
                margin-left: 2px;
                margin-right: 2px;
            }
            span , a , button{
                color: $black;
                text-transform: capitalize;
                cursor: pointer;
                min-width: 90px;
                &:focus{
                    box-shadow: 0 0 0 0.2rem rgba(255, 176, 17 , 0.25);
                }
                &.active {
                    border: 1px solid $yellow;
                }
            }
        }
    }
</style>
