import Vue from 'vue'
import store from '@/store'
import Router from 'vue-router'
import Error404 from '@/components/error-404'
Vue.use(Router)
Vue.component('router-link', Vue.options.components.RouterLink);
Vue.component('router-view', Vue.options.components.RouterView);
const router =  new Router({
	routes: [
		{
			path : '*',
			name : 'Error404',
			component: Error404,
			meta : {
				title : '404'
			}
		},
	],
	mode: 'history',
	scrollBehavior(to) {
        if (to.hash) {
            return window.scrollTo({ top: document.querySelector(to.hash).offsetTop, behavior: 'smooth' });
        }
        return window.scrollTo({ top: 0, behavior: 'smooth' });
    }
})

router.beforeEach( async function (to, from, next) {
	var isLoggedIn = store.getters['$_Seller/isLoggedIn']
	store.commit('setRouter', to)
	store.commit('setPreviousRouter', from)
	if( to.meta.requiresAuth  == false){
		if( isLoggedIn ){
			if( to.meta.failback == true ){
				next('/')
				return
			}
		}
	}else{
		if( to.matched.some(record => record.meta.requiresAuth) ){
			if( isLoggedIn) {
				var seller = await store.dispatch('$_Seller/GET_USER_INFO', {})
				if( seller ){
					let { status , data } = seller.data
                    if( status ){
						if( to.matched.some(record => record.meta.checkPlan)  == false ){
							if( data.plan_name == null ){
								next({
									name : 'SellerPlan'
								})
								return;
							}else if( data.shops.length == 0){
								let query = {}
								if (to.query['install']) {
									query = to.query
								}
								next({
									name : 'AddShoptifyStore',
									query: query
								})
								return;
							}else if(data.category_favorite.names.length == 0){
								next({
									name : 'ChoosingFavoriteCategory'
								})
								return;
							}
						}
						next()
						return;
					}
				}
			}
			next({name : 'Login'})
			return
		}
	}
	next()
})
export default router
