export default {
    toggleSidebar( {commit} , payload){
        commit('toggleSidebar' , payload);
    },
    updateBreadcrumb( {commit} , payload){
        commit('updateBreadcrumb' , payload);
    },
    setLang({commit}, payload) {
        commit('setLang', payload)
    },
    SEARCH_PRODUCT_HEADER({} , { keyword = '' , collection_id = null}){
        return new Promise((resolve , reject) =>{
            var params = {
                limit : 3
            }
            if( keyword != '' ){
                params['keyword'] = keyword;
            }
            if( collection_id && collection_id != 'all' ){
                params['collection_id'] = collection_id;
            }
            axios.get('/api/seller/products' , { params : params}).then((res)=>{
                resolve(res.data);
            }, (error) =>{
                reject(error)
            })
        })
    }
}