<template>
    <div class="your-store-container">
        <div v-if="!redirect_loading" class="store-list">
            <ul class="row">
                <li class="col col-md-4" v-for="item in shops">
                    <div class="store-item">
                        <div class="img-container">
                            <!--<img src="../../../assets/images/default/avatar.png" alt="">-->
                            <span class="avatar-name">
                                 {{item.avatar_name}}
                            </span>
                        </div>
                        <div class="store-info">
                            <a href="#">{{item.name}} <span v-if="item.shop_default"><i
                                    class="far fa-shield-check text-success m-r-5"></i> <span class="text-success">default</span></span></a>
                            <span>Imported product: {{item.imported_product}}</span>
                            <span class="date-info">Added at {{moment(item.created_at).format('LLL')}}</span>
                            <div class="store-action" v-if="!item.shop_default">
                                <span><a @click.prevent="setDefault(item)">set</a></span>
                                <a @click.prevent="showRemoveConfirmDialog(item)">remove</a>
                            </div>
                        </div>
                    </div>
                </li>
                <li class="col col-md-4">
                    <div class="store-item" @click="changeTab">
                        <div class="img-container">
                            <div class="plus-icon" @click="showDialogAddShoptify">
                                <i class="fal fa-plus"></i>
                            </div>
                        </div>
                        <div class="store-info text-warning">
                            Add more store
                        </div>
                    </div>
                </li>
            </ul>
        </div>
        <div v-else class="text-center">
            <div class="lds-dual-ring type2"></div>
        </div>
        <div class="modal fade" id="ErrorDialog" role="dialog">
            <div class="dialog-add-shoptify modal-dialog modal-md">
                <div class="modal-content">
                    <div class="modal-body">
                        <p class="add-shoptify-title-dialog text-danger m-b-50">You install error</p>
                        <div class="dialog-action">
                            <button type="button" class="btn btn-default btn-outline-secondary  btn-radius-border"
                                    data-dismiss="modal">Close
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <!--<div class="category-action">-->
        <!--<button @click="test" class="save-category btn btn-warning btn-radius-border">-->
        <!--Save-->
        <!--</button>-->
        <!--</div>-->
        <div class="modal fade" id="myModal" role="dialog">
            <div class="dialog-add-shoptify modal-dialog  modal-lg">
                <div class="modal-content">
                    <form @submit.stop.prevent="addSellerStore()">
                        <div class="modal-body">
                            <p class="add-shoptify-title-dialog">Please enter your Shopify URL</p>
                            <div class="shoptify-link-container">
                                <div class="form-group col col-5">
                                    <input :class="{'is-invalid': !isEmailValid}" v-model="store_url"
                                           class="form-control outline-type"
                                           placeholder="Example: dropsquare.myshopify.com"/>
                                    <div v-if="!isEmailValid" class="invalid-feedback">Email is invalid</div>
                                </div>
                                <span v-if="isHaveErrorDialogMessage" class="text-danger">{{errorMessage}}</span>
                            </div>
                            <div class="dialog-action">
                                <button @click="addSellerStore"
                                        class="btn btn-warning btn-radius-border m-t-25 text-white">
                                    Login
                                    <div v-if="!redirect_done" class="lds-dual-ring"></div>
                                </button>
                            </div>
                            <div class="dialog-hepper m-t-25">
                                <div>
                                    <a class="text-warning">
                                        Click here to create your own store if you haven’t use Shopify yet
                                    </a>
                                    <svg xmlns="http://www.w3.org/2000/svg" width="15.076" height="17.143"
                                         viewBox="0 0 15.076 17.143">
                                        <g id="Group_263" data-name="Group 263" transform="translate(0 0)">
                                            <path id="Path_401" data-name="Path 401"
                                                  d="M13.2,3.332a.16.16,0,0,0-.151-.138c-.069,0-1.377-.1-1.377-.1s-.909-.909-1.019-1.005a.408.408,0,0,0-.372-.041c-.014,0-.207.055-.509.151-.3-.881-.84-1.694-1.79-1.694H7.9A1.157,1.157,0,0,0,7.008,0C4.791,0,3.731,2.767,3.4,4.172c-.854.262-1.473.454-1.542.482-.482.151-.5.165-.551.62C1.253,5.6,0,15.31,0,15.31l9.776,1.831L15.076,16S13.218,3.428,13.2,3.332ZM9.225,2.368c-.248.083-.523.165-.826.262V2.451a4.36,4.36,0,0,0-.193-1.336C8.7,1.17,9.018,1.721,9.225,2.368ZM7.6,1.212A4.072,4.072,0,0,1,7.82,2.7v.1c-.537.165-1.129.344-1.707.523A2.958,2.958,0,0,1,7.6,1.212ZM6.939.592a.485.485,0,0,1,.289.1,3.671,3.671,0,0,0-1.79,2.85c-.468.151-.922.289-1.349.413C4.461,2.671,5.356.592,6.939.592Z"
                                                  transform="translate(0 0)" fill="#ffb011"/>
                                            <path id="Path_402" data-name="Path 402"
                                                  d="M74.277,15.87c-.069,0-1.377-.1-1.377-.1s-.909-.909-1.019-1.005a.262.262,0,0,0-.138-.069L71,29.818l5.3-1.143S74.442,16.1,74.428,16.022A.189.189,0,0,0,74.277,15.87Z"
                                                  transform="translate(-61.224 -12.676)" fill="#ffd071"/>
                                            <path id="Path_403" data-name="Path 403"
                                                  d="M22.459,42.862,21.812,44.8a3.07,3.07,0,0,0-1.28-.3c-1.033,0-1.074.647-1.074.812,0,.881,2.313,1.225,2.313,3.3A2.444,2.444,0,0,1,19.333,51.3,3.371,3.371,0,0,1,16.8,50.255l.454-1.487a3.208,3.208,0,0,0,1.625.757.664.664,0,0,0,.688-.661c0-1.157-1.9-1.212-1.9-3.112a3.163,3.163,0,0,1,3.47-3.153A2.77,2.77,0,0,1,22.459,42.862Z"
                                                  transform="translate(-14.487 -36.735)" fill="#fff"/>
                                        </g>
                                    </svg>
                                </div>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
        </div>
        <div class="modal fade show" id="RemoveConfirmDialog" role="dialog">
            <div class="dialog-add-shoptify modal-dialog modal-lg">
                <div class="modal-content">
                    <div class="modal-body">
                        <p class="add-shoptify-title-dialog m-b-50">Are you sure remove this store ?</p>
                        <div class="dialog-action">
                            <button type="button"
                                    class="m-r-20 btn btn-default btn-outline-secondary  btn-radius-border"
                                    data-dismiss="modal">Close
                            </button>
                            <button type="button" class="btn btn-default btn-danger  btn-radius-border"
                                    @click="removeShop">Confirm
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
    import {mapActions} from 'vuex'
    import helper from '@/plugins/helper'
    import moment from 'moment'

    export default {
        name: "your-store",
        data() {
            return {
                isInstallError: false,
                isVerifyDone: false,
                store_url: '',
                isEmailValid: true,
                shops: [],
                selected_remove: '',
                redirect_done: true,
                redirect_loading: true,
                isHaveErrorDialogMessage: false,
                errorMessage: ''
            }
        },
        methods: {
            ...mapActions({
                getShop: '$_Seller/GET_SHOPS',
                addShop: '$_Seller/ADD_SHOPS',
                shopify_verify: '$_Seller/SHOPIFY_VERIFY',
                setDefaultShop: '$_Seller/SET_DEFAULT_STORE',
                deleteShop: '$_Seller/DELETE_STORE',
            }),
            moment(date) {
                return new moment(date)
            },
            setDefault(shop) {
                this.setDefaultShop(shop.id).then(res => {
                    if (res.data.status) {
                        $notify({
                            content: `set ${shop.name} to default shop success`,
                            type: 'success'
                        });
                        this.initShops();
                    }
                })
            },
            changeTab: function (event) {
                $('.active').removeClass('active')
                $(event.target).parent('.store-item').addClass('active')
                this.$emit('change_category', '')
            },
            showDialogAddShoptify() {
                $('#myModal').modal('show')
            },
            removeShop() {
                this.deleteShop(this.selected_remove.id).then(res => {
                    if (res.data.status) {
                        $notify({
                            content: `delete ${this.selected_remove.name} shop success`,
                            type: 'success'
                        });
                        $('#RemoveConfirmDialog').modal('hide')
                        this.initShops();
                    }
                })
            },
            showRemoveConfirmDialog(shop) {
                $('#RemoveConfirmDialog').modal('show')
                this.selected_remove = shop;
            },
            addSellerStore() {
                let pattern = /^(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+myshopify.com$/g
                this.isEmailValid = pattern.test(String(this.store_url).toLowerCase());
                if (this.isEmailValid) {
                    // $('#myModal').modal('hide')
                    this.redirect_done = false
                    // loading here
                    this.addShop({shop: this.store_url}).then(res => {
                        if (res.data.status) {
                            this.store_url = ''
                            console.log(res.data);
                            // this.$route.router.go(res.data.redirect);
                            window.location.href = res.data.redirect
                            // this.$router.go()
                            // this.initShops()
                        } else {
                            this.redirect_done = true
                            // $('#myModal').modal('hide')
                            this.isHaveErrorDialogMessage = true
                            this.errorMessage = res.data.message

                        }
                    })
                } else {
                    $('#myModal').modal('show')
                }
            },
            initShops() {
                this.getShop().then(res => {
                    if (res.data.status) {
                        let temp = res.data.data;
                        temp.forEach(function (el) {
                            let chars = ''
                            el.name.split(' ').forEach(function (el2) {
                                if (chars.length < 2) {
                                    chars += el2[0].toUpperCase()
                                }
                            })
                            el.avatar_name = chars
                        })
                        this.shops = res.data.data
                        this.redirect_loading = false
                        console.log(this.redirect_loading);
                    }
                })
            },
            resetErrorMessaage() {
                this.isHaveErrorDialogMessage = false
                this.errorMessage = ''
            }
        },
        watch: {
            'isInstallError': function (value) {
                if (this.isInstallError) {
                    $('#ErrorDialog').modal('show')
                }
            }
        },
        created: function () {
            let isError = this.$route.query['install']
            if (isError == 'error') {
                this.isInstallError = true
                this.initShops()
            } else if (isError == 'success') {
                let domain = this.$route.query['myshopify_domain'] ? this.$route.query['myshopify_domain'] : ''
                let access_token = this.$route.query['access_token'] ? this.$route.query['access_token'] : ''
                let temp = {
                    myshopify_domain: domain,
                    access_token: access_token
                }
                this.shopify_verify(temp).then(res => {
                    if (res.data.status) {
                        // this.initShops()
                        this.$router.push({
                            name: "YourStore"
                        })
                        this.initShops()
                    } else {
                        this.isInstallError = true
                        this.initShops()
                    }
                })
            } else {
                this.initShops()
            }
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';
    @import '../css/add-store-dialog';

    .your-store-container {
        .store-list {
            ul {
                padding: 0px;
                list-style-type: none;
                li {
                    margin-top: 15px;
                    margin-bottom: 15px;
                    .store-item {
                        /*background: white;*/
                        display: flex;
                        padding: 0px;
                        border-radius: 10px;
                        border: solid 3px transparent;
                        .img-container {
                            /*max-height: 70px;*/
                            /*max-width: 70px;*/
                            height: 70px;
                            width: 70px;
                            border-radius: 50%;
                            padding: 4px;
                            text-align: center;
                            display: flex;
                            flex-direction: column;
                            justify-content: space-around;

                            .plus-icon {
                                border-radius: 100%;
                                border: 1px solid $yellow;
                                /*width: 55.8px;*/
                                /*height: 55.8px;*/
                                width: 90%;
                                height: 90%;
                                margin: auto;
                                position: relative;
                                &:hover {
                                    cursor: pointer;
                                }
                                i {
                                    font-size: 20px;
                                    color: $yellow;
                                    position: absolute;
                                    top: 50%;
                                    left: 50%;
                                    transform: translate(-50%, -50%);
                                }
                            }
                        }
                        .avatar-name {
                            width: 90%;
                            height: 90%;
                            margin: auto;
                            background: #EDEFF1;
                            color: #A4AFB7;
                            /*border: solid 1px lightgrey;*/
                            border-radius: 100%;
                            display: flex;
                            flex-direction: column;
                            justify-content: space-around;
                            font-size: 22px;
                        }
                        .store-info {
                            display: flex;
                            flex-direction: column;
                            justify-content: space-around;
                            .date-info {
                                color: #C9C9C9;
                            }
                            a {
                                font-weight: lighter;
                                .far {
                                    font-weight: 300;
                                }
                            }
                            .store-action {
                                display: flex;
                                a:nth-child(2) {
                                    color: $yellow;
                                }
                                span {
                                    flex: 1;
                                }
                            }
                        }
                    }
                }
            }
        }
        .category-action {
            .save-category {
                width: 100px;
                color: white
            }
        }
        .error-install-message {
            text-align: center;
            font-size: 30px;
        }
    }

    .lds-dual-ring {
        display: inline-block;
        width: 18px;
        height: 18px;
        vertical-align: middle;
        margin-left: 10px;
        &.type2 {
            width: 120px;
            height: 120px;
            margin: auto;
        }
        /*position: a;*/
    }

    .lds-dual-ring:after {
        content: " ";
        display: block;
        width: 17px;
        height: 16px;
        margin: 1px;
        border-radius: 50%;
        border: 5px solid #fff;
        border-color: #fff transparent #fff transparent;
        animation: lds-dual-ring 1.2s linear infinite;
    }

    .type2:after {
        content: " ";
        display: block;
        border-radius: 50%;
        width: 100px;
        height: 100px;
        margin: auto;
        border: 5px solid $yellow;
        border-color: $yellow transparent $yellow transparent;
    }

    @keyframes lds-dual-ring {
        0% {
            transform: rotate(0deg);
        }
        100% {
            transform: rotate(360deg);
        }
    }

</style>
