<template>
    <section class="app-home">
        <div class="app-home-container" v-if="!isLoading">
            <transition name="fade" mode="out-in">
                <router-view />
            </transition>
        </div>
    </section>
</template>
<script>
    export default {
        name: 'HomeLayout',
        data: () => {
            return {
                isLoading: false,
            }
        },
        created: async function () {
            this.isLoading = true
            await this.$store.dispatch('$_Home/GET_LIST_BANNERS', {})
            this.isLoading = false
        },
    }

</script>
<style lang="scss" scoped>
    .app-home{
        width: 100%;
        overflow: hidden;
    }
</style>

