<template>
    <button class="g-btn" @click="login" type="button">
        <i class="fab fa-google-plus-g"></i>
    </button>
</template>

<script>
    import GAuth from 'vue-google-oauth2'
    import Vue from 'vue'
    export default {
        name: "gglogin",
        props:{
            appId : {
                
            }
        },
        methods: {
            login() {
                this.$gAuth.signIn()
                    .then(GoogleUser => {
                        this.$emit('Login',GoogleUser)
                        this.isSignIn = this.$gAuth.isAuthorized
                    })
                    .catch(error => {
                        console.log(error);
                    })
            }
        },
        mounted(){
            const gauthOption = {
                clientId: this.appId,
                scope: 'profile email',
                prompt: 'consent'
            }
            Vue.use(GAuth, gauthOption)
        }
    }
</script>

