export default {
    LOGIN_SUCCESS(state , { token , remember = false}){
        state.isLoggedIn = true
        state.token = token 
        state.remember = remember
        localStorage.setItem('token' , token )
        localStorage.setItem('remember' , remember )
        axios.defaults.headers.common['Authorization'] = token
        if( remember ){
            localStorage.removeItem('token_expired')
        }else{
            localStorage.setItem('token_expired' , new Date().getTime() + state.remember_timeout  )
            if( EventBus ){
                EventBus.$emit('set-check-token-expired')
            }
        }
    },
    UPDATE_LOGIN_TIMEOUT(state){
        if( state.isLoggedIn ){
            if( state.remember == false ){
                localStorage.setItem('token_expired' , new Date().getTime() + state.remember_timeout  )
            }else{
                localStorage.removeItem('token_expired')
            }
        }
    },
    LOGOUT_SUCCESS(state ){
        state.isLoggedIn = false
        state.token = null
        localStorage.removeItem('token')
        localStorage.removeItem('token_expired')
        localStorage.removeItem('remember')
        delete axios.defaults.headers.common['Authorization']
    },
    UPDATE_SELLER_INFO( state , payload){
        state.seller = payload
    }
}