<template>
    <div class="container">
        <div class="col col-md-6 login-left-form">
            <div class="product-filter-title m-b-25">
                <span>Reset Password</span>
            </div>
            <form @submit.stop.prevent="onSubmitResetPassword()">
                <div class="form-group reset-password-form">
                    <label class="input-title">Password <span class="text-danger">*</span></label>
                    <input v-model="password" :class="{'is-invalid': isInvalid}" class="form-control outline-type"
                           type="password"/>
                    <div class="invalid-feedback">
                        <span>Password and confirm password must be same</span>
                    </div>
                </div>
                <div class="form-group reset-password-form">
                    <label class="input-title">Confirm password <span class="text-danger">*</span></label>
                    <input v-model="confirmPassword" :class="{'is-invalid': isInvalid}"
                           class="form-control outline-type" type="password"/>
                    <div class="invalid-feedback">
                        <span>Password and confirm password must be same</span>
                    </div>
                </div>
                <div class="reset-password-action m-t-25">
                    <button class="btn btn-warning btn-radius-border text-white">
                        Reset
                    </button>
                </div>
            </form>
        </div>

    </div>
</template>

<script>
    import {mapActions} from 'vuex'

    export default {
        name: "forgot-password",
        data() {
            return {
                isInvalid: false,
                password: '',
                confirmPassword: '',
                token: ''
            }
        },
        methods: {
            ...mapActions({
                checkToken: "$_Seller/CHECK_TOKEN",
                resetPassword: "$_Seller/RESET_PASSWORD"
            }),
            onSubmitResetPassword() {
                if (this.password != this.confirmPassword) {
                    this.isInvalid = true
                } else {
                    let temp = {
                        reset_password_token: this.token,
                        new_password: this.password
                    }
                    this.resetPassword(temp).then(res => {
                        if (res.data.status) {
                            this.$store.commit('$_Seller/LOGIN_SUCCESS', res.data.data.token)
                            this.redirect({
                                name: "Home"
                            })
                        } else {
                            $notify({
                                content: res.data.message,
                                type: "danger"
                            })
                        }
                    })
                }
            }
        },
        created: function () {
            let token = this.$route.query['id']
            this.token = token
            console.log(token);
            this.checkToken(token).then(res => {
                if (!res.data.status) {
                    this.redirect({
                        name: 'Error404'
                    })
                }
            })
        }
    }
</script>

<style lang="scss" scoped>
    .reset-password-action {
        button {
            min-width: 150px;
        }
    }

    .reset-password-form {
        input {
            max-width: 350px;
        }
    }
</style>
