<template>
    <div class="app-collection-breadcrumb">
        <nav class="app-collection-breadcrumb-nav">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"  >
                    <router-link  :to="{name : 'Home'}">
                        Home
                    </router-link>
                </li>
                <li class="breadcrumb-item"  >
                    <router-link  :to="setRouterLink()">
                        All collections
                    </router-link>
                </li>
                <li class="breadcrumb-item" v-for="(item , index) in data " :key="`index_${index}`" :class="{'is-disabled' : disabled && index == data.length - 1 }" >
                    <router-link :title="item.title" :to="setRouterLink(item)">
                        {{item.title}}
                    </router-link>
                </li>
            </ol>
        </nav>
    </div>
</template>
<script>
import helper from '@/plugins/helper'
export default {
    name : 'CollectionBreadcrumb',
    props:{
        data : {
            type : Array
        },
        disabled : {
            default : true,
        }
    },
    methods:{
        setRouterLink(item = null){
            var query = {}
            if( this.$route.name == 'Collection'){
                query = JSON.parse( JSON.stringify(this.$route.query) )
                if( query.hasOwnProperty('page')){
                    delete query['page']
                }
            }
            var object =  {
                name : 'Collection',
                params :{},
                query : query
            }
            var slug = '' 
            if( item ){
                object.params['id'] = helper.toSlug(item.title) + '-'+ item.id
            }
            return this.setRouterLinkDefault(object)
        },
    }
}
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-collection-breadcrumb{
        &-nav{
            .breadcrumb{
                background: transparent;
                padding: 0;
                margin: 0;
                li{
                    a{
                        padding: 0 5px;
                        color:$text-color;
                        text-decoration: none;
                        &:hover{
                            color:$yellow;
                        }
                    }
                    &.disabled{
                        a{
                            color:$text-color;
                            opacity: 0.7;
                            &:hover{
                                color:$text-color;
                            }
                        }
                    }
                }
                .breadcrumb-item + .breadcrumb-item::before {
                    content: "\f054";
                    @include fontawesome;
                    display: inline-block;
                    padding-right: 0.5rem;
                    color: #6c757d;
                    font-weight: 300;
                    
                }
            }
        }
        
    }
</style>
