<template>
	<div class="app-search">
        <div class="app-search-head">
            <div class="container">
                <div class="row">
                    <div class="col col-12">
                        <p>
                            Found <strong>{{pagination.total}}</strong> result for <strong>{{keyword}}</strong> in <strong>{{collection}}</strong>
                        </p>
                    </div>
                </div>
            </div>
        </div>
        <div class="app-search-container container">
            <div class="app-search-row row">
                <div class="app-search-col app-search-col-sidebar col">
                    <app-sidebar></app-sidebar>
                </div>
                <div class="app-search-col app-search-col-content col">
                    <tab-filter-router></tab-filter-router>
                    <transition name="fade-transform" mode="out-in">
                        <div class="row" v-if="isLoading" key="list-product-loading">
                            <div class="col col-12">
                                <product-loading :limit="pagination.limit" col="col col-md-4 col-lg-3 m-b-30"></product-loading>
                            </div>
                        </div>
                        <div  v-else key="row list-product-ready">
                            <template v-if="products.length">
                                <list-products :products="products" col="col col-md-4 col-lg-3 m-b-30" :has-banner="false"></list-products>
                                <div class="text-center">
                                    <pagination v-model="pagination.current_page" :total="pagination.total_page"></pagination>
                                </div>
                            </template>
                            <template v-else>
                                <div class="col col-12 ">
                                    <product-empty>
                                        <p>Sorry, we couldn't find any content for</p>
                                        <p><strong>{{keyword}}</strong> in <strong>{{collection}}</strong></p>
                                    </product-empty>
                                </div>
                            </template>
                        </div>
                    </transition>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
    import ProductEmpty from '../partials/product-empty'
    import ProductLoading from '../partials/product-loading'
    import ListProducts from '../partials/list-products'
    import AppSidebar from '../partials/sidebar'
    import TabFilterRouter from '../partials/tab-filter-router'
    import { mapGetters } from 'vuex';
    import helper from '@/plugins/helper'
    import Pagination  from '@/components/pagination'
	export default{
        name : 'Search',
        components: {
            AppSidebar , TabFilterRouter ,ListProducts , Pagination , ProductEmpty , ProductLoading
        },
        metaInfo() {
            return {
                title: this.meta.title,
            }
        },
        data(){
            return {
                isLoading: false,
                sortables : ['last' ,'trending' ,'price'],
                collection_id : '',
                products : [],
                default_sort : 'last',
                meta:{
                    title : 'All Collections'
                },
                pagination : {
                    limit : 20,
                    total : 0,
                    total_page : 0,
                    current_page : 1,
                },
                collection : '',
                keyword : ''
            }
        },
        computed: {
            ...mapGetters({
                collections : '$_Home/getCollections',
                countries : '$_Home/getCountries'
            })
        },
        methods: {
            setKeywordAndCollection(keyword , collection_id){
                this.keyword = keyword
                var find = _.find(this.collections , { id : collection_id })
                if( find ){
                    this.collection = find.title
                }else{
                    this.collection = 'All Collections'
                }
            },
            getProduct(to = null){
                if( to == null){
                    to = this.$route
                }
                let sort = to.query.sort ? to.query.sort : null 
                sort = this.checkSort(sort) ? sort : this.default_sort
                let keyword = to.query.keyword ? to.query.keyword : null 
                /* get current_page */
                let page = to.query.page   ? to.query.page : 1
                if( page ) {
                    page = helper.isNumeric(page) ? page : 1
                }
                /* get collection_id */
                let collection_id = to.query.collection_id   ? to.query.collection_id : null
                if( collection_id ) {
                    collection_id = this.checkCollection(collection_id) ? collection_id : null
                }
                /* get supplier_id */
                let supplier_id = to.query.supplier_id  ? to.query.supplier_id : null 
                if( supplier_id ) {
                    supplier_id = this.checkSupplier(supplier_id) ? supplier_id : null
                }
                /* get shipping_from */
                let shipping_from = to.query.shipping_from ?  to.query.shipping_from : null
                if( shipping_from ){
                    shipping_from = this.checkCountry(shipping_from) ? shipping_from : null
                }
                /* get shipping_to */
                let shipping_to = to.query.shipping_to  ? to.query.shipping_to : null
                if( shipping_to ){
                    shipping_to = this.checkCountry(shipping_to) ? shipping_to : null
                }
                /* get prices */
                let prices = null
                let price = to.query.prices 
                if( price ){
                    var temp = price.split('-')
                    if( temp.length == 2){
                        var min = temp[0].trim()
                        var max = temp[1].trim()
                        if( helper.isNumeric(min) && helper.isNumeric(max) && parseInt(min) <= parseInt(max)){
                            prices = price
                        }
                    }
                }
                this.setKeywordAndCollection( keyword , collection_id)
                return new Promise((resolve , reject )=>{
                    this.$store.dispatch('$_Home/GET_LIST_PRODUCTS' , { 
                        sort : sort,
                        collection_id: collection_id,
                        page : page,
                        supplier_id: supplier_id,
                        shipping_from : shipping_from,
                        shipping_to : shipping_to,
                        prices : prices,
                        limit : this.pagination.limit,
                        keyword : keyword
                    }).then(res=>{
                        let { status , data , pagination } = res
                        if( status ){
                            this.products = data
                            this.pagination.total = parseInt(pagination.total) 
                            this.pagination.total_page = parseInt(pagination.total_page ) 
                            this.pagination.current_page = parseInt(pagination.current_page) 
                        }
                    })
                    resolve()
                })
            },
            checkCountry(code){
                return  _.find(this.countries , { code : code}) != undefined
            },
            checkSupplier(id){
                return _.find(this.suppliers , { id : id}) != undefined
            },
            checkSort(sort){
                return this.sortables.indexOf(sort) >= 0 
            },
            checkCollection(collection_id){
                return  _.find(this.collections , { id : collection_id}) != undefined
            }
        },
        beforeRouteUpdate : async function(to, from, next) {
            this.isLoading = true
            await this.getProduct(to)
            this.isLoading = false
            next()
        },
        created : async function(){
            this.isLoading = true
            var to = this.$route
            await this.getProduct(this.$route)
            this.isLoading = false
        }
    }
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';
    $search-head : #F2F2F2;
    .app-search{
        
        &-head{
            background: $search-head;
            padding: 50px 0;
            text-align: center;
            p{
                margin: 0;
                font-size: 20px;
                font-weight: normal;
                strong{
                    font-weight: bold;
                }
            }
        }
        &-container{
            padding: 20px 0;
        }
        &-row{

        }
        &-col{
            &-sidebar{
                max-width: 20%;
            }
            &-content{
                max-width: 80%;
            }
        }
    }
</style>