
import layout  from '../_components/layout'
import Home  from '../_components/home'
import Collection  from '../_components/collection'
import Premium  from '../_components/premium'
import Search  from '../_components/search'
import ProductDetail  from '../_components/product'

export default {
    path : '/',
    component: layout,
    meta : {
        requiresAuth : false,
        roles : [],
    },
    children :[
        {
            path : '',
            name : 'Home',
            component: Home,
            meta : {

            },
        },
        {
            path : 'collections/:id?',
            name : 'Collection',
            component: Collection,
            meta : {

            },
        },
        {
            path : 'premiums',
            name : 'Premiums',
            component: Premium,
            meta : {

            },
        },
        {
            path : 'search',
            name : 'Search',
            component: Search,
            meta : {

            },
        },
        {
            path : 'product/:id',
            name : 'ProductDetail',
            component: ProductDetail,
            meta : {
                
            },
        }
    ]
}

