<template>
    <div class="login-container">
        <div class="login-form row">
            <div @click="formFocus('login-form')" :class="{'form-opacity':!isLoginFocus}" class="col col-5">
                <div class="form-inner">
                    <transition name="fade-transform" mode="out-in">
                        <form-login :mode.sync="isLoginMode" v-if="isLoginMode" key="is-form-login"></form-login>
                        <form-forgot-password :mode.sync="isLoginMode" v-else key="is-form-forgot-password"></form-forgot-password>
                    </transition>
                </div>
            </div>
            <div class="col col-2 form-center-line"></div>
            <div @click="formFocus" :class="{'form-opacity':isLoginFocus}" class="col col-5">
                <form-register></form-register>
            </div>
        </div>
        
    </div>
</template>

<script>
    import {required, minLength, email, sameAs} from 'vuelidate/lib/validators'
    import {mapGetters, mapActions} from 'vuex';
    import helper from '@/plugins/helper';
    import FormLogin from './auth/login';
    import FormForgotPassword from './auth/forgot-password';
    import FormRegister from './auth/register';
    export default {
        name: "LoginAndRegister",
        components: {
            FormLogin , FormForgotPassword , FormRegister
        },
        data() {
            return {
                isLoginMode : true,
                isLoginFocus: true,
            }
        },
        methods: {
            formFocus(isLogin) {
                if (isLogin == "login-form") {
                    this.isLoginFocus = true
                } else {
                    this.isLoginFocus = false
                }
            },
        },
       
    }
</script>


