<template>
    <div>
        <transition name="fade" mode="out-in">
            <div class="easyzoom easyzoom--adjacent" ref="img" v-if="ready" key="is_ready">
                <a :href="src" >
                    <img :src="src" class="img-fluid">
                </a>
            </div>
        </transition>
    </div>
</template>
<script>

export default {
    name : 'ImageZoomer',
    props :{
        src :{
            required : true
        }
    },
    data(){
        return {
            ready : false,
        }
    },
    watch :{
        'src' : function(src){
            this.ready = false
            this.$nextTick(()=>{
                this.ready = true
                this.$nextTick(()=>{
                    $(this.$refs.img).easyZoom();
                })
            })
        }
    },
    mounted(){
        if( this.src ){
            this.ready = true
            this.$nextTick(()=>{
                $(this.$refs.img).easyZoom();
            })
        }
    },
}
</script>
<style lang="scss" scoped>
    .easyzoom-img{
        max-width: 100%;
        height: auto;
    }
</style>

