<template>
    <section class="app-seller">
        <div class="app-seller-page">
            <transition :css="false" @before-enter="fadeBeforeEnter" @enter="fadeEnter" @leave="fadeLeave"
                        mode="out-in">
                <div class="container" v-if="!isLoading">
                    <div class="row">
                        <transition :css="false" @before-enter="fadeBeforeEnter" @enter="fadeEnter" @leave="fadeLeave"
                                    mode="out-in">
                            <div class="col col-sidebar" v-if="hasSidebar">
                                <div class="app-seller-sidebar">
                                    <app-sidebar></app-sidebar>
                                </div>
                            </div>
                        </transition>
                        <div class="col col-content">
                            <div>
                                <div v-if="title" class="title-container">
                                    <div class="product-filter-title m-b-25">
                                        <span>{{title}}</span>
                                    </div>
                                </div>
                                <transition name="fade" mode="out-in">
                                    <router-view/>
                                </transition>
                            </div>

                        </div>
                    </div>
                </div>
            </transition>
        </div>
    </section>
</template>
<script>
    import AppSidebar from './partials/sidebar'

    export default {
        name: 'SellerLayout',
        components: {
            AppSidebar
        },
        data() {
            return {
                isLoading: true,
                routers_has_sidebar: ['Seller', 'Account', 'YourStore', 'Subscription', 'Pricing', 'YourCategories'],
                title: ""

            }
        },
        computed: {
            hasSidebar() {
                this.title = this.$route.meta.title
                return this.routers_has_sidebar.indexOf(this.$route.name) >= 0
            }
        },
        methods: {},

        created: async function () {
            this.isLoading = false
        }
    }
</script>

<style lang="scss">
    .app-seller-page {
        padding: 30px 0;
        .col-sidebar {
            max-width: 240px;
            margin-top: 5px;
        }
    }
</style>
