<template>
    <div></div>
</template>
<script>
import { mapGetters, mapActions } from 'vuex';
import moment from 'moment'
export default {
    name : 'LoginTimeout',
    data(){
        return {
            timeout : null,
            date : null,
            token_expired : null,
        }
    },
    computed:{
        ...mapGetters({
            isLogin : '$_Seller/isLoggedIn',
            router : 'getRouter'
        }),
    },
    methods :{
        ...mapActions({
            logout : '$_Seller/LOGOUT',
        }),
        checkTokenExpried(){
            var date  = new Date().getTime()
            var token_expired =  localStorage.getItem('token_expired')
            if( token_expired  && this.isLogin ){
                token_expired = parseInt(token_expired)
                if( date > token_expired){
                    this.logout()
                    if( this.router.matched.some(record => record.meta.requiresAuth) ){
                        this.redirect({name : 'Login'})
                    }
                }
            }else{
                clearInterval(this.timeout)
            }
        },
        setcheckTokenExpried(){
            clearInterval(this.timeout)
            this.timeout = setInterval( ()=>{
                this.checkTokenExpried()
            }, 1000);
        },
    },
    mounted(){
        this.setcheckTokenExpried()
        EventBus.$on('set-check-token-expired' , ()=>{
            setTimeout( () => {
                this.setcheckTokenExpried()
            }, 1000);
        })
    },
    destroyed(){
        EventBus.$off('set-check-token-expired')
    }
}
</script>
