<template>
    <div class="subscription-container">
        <div class="subscription-table-container">
            <table class="subscription-table table">
                <thead>
                <tr>
                    <th>Membership</th>
                    <th>Subscription</th>
                    <th>Active</th>
                    <th>Created</th>
                    <th></th>
                </tr>
                </thead>
                <tbody>
                <tr>
                    <td>
                        <p>Monthly subscription</p>
                        <p class="text-warning">{{data.stripe_subscription_id}}</p>
                    </td>
                    <td>
                        <p class="text-warning">1 week for free then {{data.price}} / month</p>
                        <p class="text-warning" v-if="data.invoice_upcoming">Next Billing:
                            {{moment(data.invoice_upcoming).format("LL")}}</p>
                    </td>
                    <td class="text-danger">
                        {{data.subscription_active?"Yes":"No"}}
                    </td>
                    <td>{{moment(data.subscription_date).format("LL")}}</td>
                    <td><span class="action-link text-warning" v-if="data.plan_name!='free'" @click="cancel_subscription">Cancel</span></td>
                </tr>
                </tbody>
            </table>
        </div>
        <div class="row">
            <div v-if="data.subscription_payment_history.length" class="title-container col col-6">
                <div class="product-filter-title">
                    <span>Payment History</span>
                </div>
                <div class="subscription-table-container">
                    <table class="hisotry-table table">
                        <thead>
                        <tr>
                            <th>Payment</th>
                            <th>Date</th>
                            <th>Amount</th>
                        </tr>
                        </thead>
                        <tbody>
                        <tr v-for="item in data.subscription_payment_history">
                            <td class="text-warning">{{item.plan_name.toUpperCase()}}</td>
                            <td>{{moment(item.created_at).format("LL")}}</td>
                            <td class="text-warning">${{item.price}}</td>
                        </tr>
                        </tbody>
                    </table>
                    <nav class="mt-4">
                        <pagination :routerLink="false" :disabled="false" :total="pagination.total_page"
                                    :change="initPaymentHistory" v-model="pagination.current_page"></pagination>
                    </nav>
                </div>
            </div>
            <div v-if="cardInfo" class="title-container col col-6">
                <div class="product-filter-title">
                    <span>Payment Setting</span>
                </div>
                <div class="subscription-table-container">
                    <table class="hisotry-table table">
                        <thead>
                        <tr>
                            <th>Card Number</th>
                            <th>Expiry Date</th>
                            <th></th>
                        </tr>
                        </thead>
                        <tbody>
                        <tr>
                            <td>
                                <div class="card-type-img">
                                    <img v-if="cardInfo.type == 'Visa'" src="../../../assets/images/icons/visa.png">
                                    <img v-if="cardInfo.type == 'Master'"
                                         src="../../../assets/images/icons/master.png" alt="">
                                </div>
                                **** **** **** {{cardInfo.number}}
                            </td>
                            <td>{{cardInfo.expire_date}}</td>
                            <td><span class="action-link text-warning" @click="isCardDialogShow = true">Change</span>
                            </td>
                        </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
        <carddialog :isShow="isCardDialogShow" @modalHide="isCardDialogShow=false"
                    @dialogConfirm="changePaymentAcount"></carddialog>
    </div>
</template>

<script>
    import {mapActions} from 'vuex'
    import moment from 'moment'
    import carddialog from './card-dialog'
    import pagination from '@/components/pagination'

    export default {
        name: "subscription",
        data() {
            return {
                data: {
                    subscription_payment_history: []
                },
                pagination: {
                    total_page: 0
                },
                cardInfo: {},
                isCardDialogShow: false
            }
        },
        components: {
            carddialog, pagination
        },
        methods: {
            ...mapActions({
                getPaymentHistory: '$_Seller/GET_PAYMENT_HISTORY',
                changeCard: '$_Seller/CHANGE_PAYMENT_ACCOUNT',
                cancelSubscription: '$_Seller/CANCEL_SUBSCRIPTION'
            }),
            moment(date) {
                return moment(date)
            },
            initPaymentHistory: function (page) {
                this.getPaymentHistory(page).then(res => {
                    console.log(res.data);
                    this.data = res.data.data
                    this.pagination = res.data.pagination
                    this.cardInfo = res.data.info_card
                    console.log(this.pagination);
                })
            },
            cancel_subscription() {
              this.cancelSubscription().then(res => {
                  if (res.data.status) {
                      $notify({
                          content: "Cancel subscription success",
                          type: "success",

                      })
                      this.initPaymentHistory();
                  }
              })
            },
            changePaymentAcount(cardInfo) {
                // this.isCardDialogShow = true
                let democart = {
                    "card_no": cardInfo.card_no.replace(/\W/gi, ''),
                    "ccExpiryMonth": cardInfo.expire_date.split('/')[0],
                    "ccExpiryYear": cardInfo.expire_date.split('/')[1],
                    "cvvNumber": cardInfo.secure_code,
                }
                this.isCardDialogShow = false
                this.changeCard(democart).then(res => {
                    if (res.data.status) {
                        $notify({
                            content: "Change card success",
                            type: "success"
                        })
                        this.initPaymentHistory()
                    } else {
                        $notify({
                            content: "Change card fail",
                            type: "danger"
                        })
                        this.isCardDialogShow = true
                    }

                })

            },
        },
        created: function () {
            let page = this.$route.query['page'];
            this.initPaymentHistory(page)
        }
    }
</script>

<style lang="scss" scoped>
    .subscription-container {
        .product-filter-title {
            margin-bottom: 35px;
        }
        .subscription-table-container {
            .hisotry-table {
                /*width: auto;*/
                /*min-width: 50%;*/
            }
            .action-link {
                &:hover {
                    cursor: pointer;
                }
            }
            .card-type-img {
                display: inline-block;
                margin-right: 10px;
                img {
                    width: 30px;
                }
            }
        }
    }
</style>
