<template>
    <div class="category-container">
        <div class="category-list m-b-25" :class="{'not-selected': !is_selected}">
            <ul class="row">
                <li class="col col-md-4" v-for="item in data">
                    <div class="category-item" :class="{'active': item.favorite}"
                         @click="changeTab(item, $event)">
                        <img v-if="item.feature_image" :src="item.feature_image" alt="">
                        <img v-if="!item.feature_image" src="../../../assets/images/default/product.png" alt="">
                        <span>{{item.title}}</span>
                    </div>
                </li>
            </ul>
        </div>
        <div class="category-action">
            <button v-if="button_content" @click="saveFavoriteCategory" class="save-category btn btn-warning btn-radius-border">
                {{button_content}}
            </button>
            <button v-else @click="saveFavoriteCategory" class="save-category btn btn-warning btn-radius-border">
                Save
            </button>
        </div>
    </div>
</template>

<script>
    import {mapActions} from 'vuex'

    export default {
        name: "category",
        props: ["selected", "button_content"],
        data() {
            return {
                data: [],
                current_selected: [],
                is_selected: true,
            }
        },
        methods: {
            ...mapActions({
                getSellerCategory: '$_Seller/getSellerCategory',
                updateFavoriteCollection: '$_Seller/UPDATE_FAVORITE_COLLECTION',
                getSellerFavoriteCategory: '$_Seller/GET_FAVORITE_CATEGORY',
            }),
            changeTab: function (item, event) {
                let parent = $(event.target).parent('.category-item')
                if (parent.hasClass('active')) {
                    parent.removeClass('active')
                } else {
                    parent.addClass('active')
                    this.is_selected = true
                }
                item.favorite = !item.favorite
            },
            saveFavoriteCategory: function () {
                let currentSelected = this.data.filter(function (el) {
                    return el.favorite
                }).map(function (el) {
                    return el.id
                })
                if (currentSelected.length > 0) {
                    this.updateFavoriteCollection(currentSelected).then(res => {
                        if (res.data.status) {
                            this.$emit('change_category', currentSelected)
                            $notify({
                                content: "Save success",
                                type: "success"
                            })
                        }
                    })
                } else {
                    this.is_selected = false
                    $notify({
                        content: "You must choose at least one category",
                        type: "danger"
                    })
                }
            }
        },
        created: function () {
            let that = this;
            this.getSellerCategory().then(function (res) {
                that.data = res.data.data
                that.getSellerFavoriteCategory().then(function (res) {
                    console.log(res.data);
                    if (res.data.status) {
                        that.data = that.data.map(function (el) {
                            el.favorite = res.data.data.includes(el.id)
                            return el
                        })
                    }
                })
            })
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';

    .category-container {
        .category-list {
            background: #DCDCDC;
            padding: 24px;
            max-height: 510px;
            overflow-y: scroll;
            transition: all .4s;
            &.not-selected {
                border: solid 2px red;
            }
            ul {
                padding: 0px;
                list-style-type: none;
                li {
                    margin-top: 15px;
                    margin-bottom: 15px;

                    .category-item {
                        background: white;
                        display: flex;
                        padding: 0px;
                        border-radius: 10px;
                        border: solid 3px transparent;
                        &.active.category-item {
                            border-color: $yellow;
                        }
                        &:hover {
                            cursor: pointer;
                        }
                        img {
                            max-height: 122px;
                            max-width: 122px;
                        }
                        span {
                            /*width: 60%;*/
                            display: flex;
                            justify-content: center;
                            flex-direction: column;
                            text-align: center;
                            flex: 1;
                            vertical-align: middle;
                            padding: 10px;
                        }
                    }
                }
            }
        }

        .category-action {
            .save-category {
                min-width: 150px;
                color: white
            }
        }
    }
</style>
