<template>
    <div class="product-detail">
        <transition name="fade" mode="out-in">
            <div class="product-detail-container-loading" v-if="isLoading" key="is-loading">
                <i class="icon-loading"></i>
            </div>
            <div class="product-detail-container" v-else key="is-loaded">
                <template v-if="error">
                    <error></error>
                </template>
                <template v-else>
                    <div class="product-breadcrumb">
                        <div class="container">
                            <div class="row">
                                <div class="col col-12">
                                    <breadcrumb :data="breadcrumb"></breadcrumb>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="product-detail-sticky-bar" ref="sticky">
                        <div class="container">
                            <div class="detail-sticky">
                                <div class="sticky-bar-item">
                                    <span class="product-name m-r-20">
                                        {{data.title}}
                                    </span>
                                    <span class="supplier-name">
                                        by <a href="" class="text-warning" v-if="data.supplier">{{data.supplier.shop_name}}</a>
                                    </span>
                                </div>
                                <div class="sticky-bar-item">
                                    <span class="product-price m-r-10">{{data.price_max != data.price_min?data.price_max+ "$" +" - "+ data.price_min+ "$":data.price_min + "$"}}</span>
                                </div>
                                <div class="sticky-bar-item">
                                    <div class="import-actions">
                                        <button type="button" v-if="!data.isImported"
                                                @click.stop.prevent="importProduct(data, $event)"
                                                :class="{'btn-importing': isImportLoading}"
                                                class="btn btn-warning btn-import-list btn-radius-border">
                                            <i class="icon-load fas fa-shopping-bag"></i>
                                            <div class="circle-loader">
                                                <div class="checkmark draw"></div>
                                            </div>
                                            Add to Import List
                                        </button>
                                        <button v-if="data.isImported"
                                                @click.stop.prevent="removeImported(data, $event)"
                                                :class="{'btn-importing': isImportLoading}"
                                                class="btn black-button-style btn-radius-border">
                                            <i class="icon-load fas fa-trash"></i>
                                            <div class="circle-loader">
                                                <div class="checkmark draw"></div>
                                            </div>
                                            Remove imported list
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="product-head" ref="body">
                        <div class="container">
                            <div class="row">
                                <div class="col col-6">
                                    <div class="product-image">
                                        <div class="product-image-box">
                                            <image-zoomer :src="activeImage"></image-zoomer>
                                        </div>
                                        <div class="product-image-carousel">
                                            <carousel v-bind="carousel">
                                                <slide v-for="(item , index) in data.images" :key="`slide_${index}`"
                                                       :data-index="index" @slideclick="onClickSlide">
                                                    <div class="item-slide"
                                                         :class="{ 'is-active' : activeSlide == index}">
                                                        <img :src="item.src" alt="">
                                                    </div>
                                                </slide>
                                            </carousel>
                                        </div>
                                    </div>
                                </div>
                                <div class="col col-6">
                                    <div class="product-title">
                                        <h1>{{data.title}}</h1>
                                    </div>
                                    <div class="product-supplier">
                                        <span>By</span>
                                        <strong>{{data.supplier.shop_name}}</strong>
                                    </div>
                                    <div class="product-short-description">
                                        <p>
                                            {{ data.short_description}}
                                        </p>
                                    </div>
                                    <div class="product-properties">
                                        <div class="item-property" v-for="(property , index ) in form.properties"
                                             :key="`property_${index}`">
                                            <div class="item-property-title">{{ property.name }}</div>
                                            <div class="item-property-value">
                                                <div class="item-value" v-for="(item, i) in property.data"
                                                     :key="`value_index${i}`"
                                                     :class="{ 'is-active' : activeOption({option : property.id , value : item.id }) }">
                                                    <template v-if="item.image && item.image.src">
                                                        <button @click.stop.prevent="selectOption(property.id , item.id , item.image )"
                                                                type="button" class="btn btn-sm item-value-image"
                                                                :title="item.name">
                                                            <img :src="item.image.src" alt="">
                                                        </button>
                                                    </template>
                                                    <template v-else>
                                                        <button @click.stop.prevent="selectOption(property.id , item.id)"
                                                                type="button" class="btn btn-sm item-value-text">
                                                            {{item.name}}
                                                        </button>
                                                    </template>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    <div class="product-price">
                                        <div class="item-price-title">Price</div>
                                        <transition name="fade-transform" mode="out-in">
                                            <div class="item-price-value" v-if="selectedProduct.is_selected"
                                                 key="price_1">
                                                {{selectedProduct.price }}
                                            </div>
                                            <div class="item-price-value" v-else key="price_2">
                                                {{selectedProduct.price }}
                                            </div>
                                        </transition>
                                    </div>
                                    <div class="product-inventory">
                                        <transition name="fade-transform" mode="out-in">
                                            <div v-if="selectedProduct.is_selected" key="inventory_1">
                                                <span>Availability :</span> <strong>{{selectedProduct.inventory |
                                                number_format }} in stock</strong>
                                            </div>
                                            <div v-else key="inventory_2">
                                                <span>Availability :</span> <strong>{{data.inventory | number_format }}
                                                for {{data.variants.length}} variants in stock</strong>
                                            </div>
                                        </transition>
                                    </div>
                                    <div class="product-actions">
                                        <button type="button" v-if="!data.isImported"
                                                @click.stop.prevent="importProduct(data, $event)"
                                                :class="{'btn-importing': isImportLoading}"
                                                class="btn btn-warning btn-import-list">
                                            <i class="icon-load fas fa-shopping-bag"></i>
                                            <div class="circle-loader">
                                                <div class="checkmark draw"></div>
                                            </div>
                                            Add to Import List
                                        </button>
                                        <button v-if="data.isImported"
                                                @click.stop.prevent="removeImported(data, $event)"
                                                :class="{'btn-importing': isImportLoading}"
                                                class="btn black-button-style">
                                            <i class="icon-load fas fa-trash"></i>
                                            <div class="circle-loader">
                                                <div class="checkmark draw"></div>
                                            </div>
                                            Remove imported list
                                        </button>
                                    </div>
                                    <hr>
                                    <div class="product-shipping">
                                        <div class="item-shipping">
                                            <div class="item-title">
                                                READY TO SHIP IN
                                            </div>
                                            <div class="item-value">
                                                {{data.process_time}} days
                                            </div>
                                        </div>
                                        <div class="item-shipping">
                                            <div class="item-title">
                                                RETURN POLICY
                                            </div>
                                            <div class="item-value">
                                                {{data.return_policy}} days
                                                <p>
                                                    Returns accepted if product not as described, buyer pays return
                                                    shipping fee; or keep the product & agree refund with seller. <a
                                                        href="#">View details</a>
                                                </p>

                                            </div>
                                        </div>
                                        <div class="item-shipping-methods">
                                            <div class="item-title">
                                                SHIPPING TIME
                                            </div>
                                            <div class="list-shipping-country">
                                                <div class="item-warehouse">
                                                    <div class="item-warehouse-shipping item-warehouse-shipping-head">
                                                        <div class="item-country">
                                                            &nbsp;
                                                        </div>
                                                        <div class="item-shipping-cost">
                                                            Shipping Cost
                                                        </div>
                                                        <div class="item-shipping-fee">
                                                            Incremental Fee
                                                        </div>
                                                        <div class="item-shipping-from">
                                                            From
                                                        </div>
                                                        <div class="item-shipping-to">
                                                            To
                                                        </div>
                                                    </div>
                                                </div>
                                                <div class="item-warehouse"
                                                     v-for="(warehouse , warehouse_index ) in productShippings"
                                                     :key="`warehouse_${warehouse_index}`">
                                                    <div class="item-warehouse-name">
                                                        {{warehouse.country_name}}
                                                    </div>
                                                    <div class="item-warehouse-shipping"
                                                         v-for="(shipping , index ) in warehouse.shippings"
                                                         :key="`shipping_${index}`">
                                                        <div class="item-country">
                                                            <template v-if="shipping.rest_of_countries">
                                                                Worldwide
                                                            </template>
                                                            <template v-else>
                                                                <list-flag v-model="shipping.countries"></list-flag>
                                                            </template>
                                                        </div>
                                                        <div class="item-shipping-cost">
                                                            ${{shipping.price | number_format}}
                                                        </div>
                                                        <div class="item-shipping-fee">
                                                            ${{shipping.incremental_fee | number_format}}
                                                        </div>
                                                        <div class="item-shipping-from">
                                                            {{shipping.estimate_time_from}}
                                                        </div>
                                                        <div class="item-shipping-to">
                                                            {{shipping.estimate_time_to}}
                                                        </div>
                                                    </div>
                                                </div>
                                                <div class="item-warehouse">
                                                    <div class="item-warehouse-except">
                                                        Do not ship to {{ data.except_shipping}}
                                                    </div>
                                                </div>
                                            </div>
                                        </div>

                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="product-body">
                        <div class="container">
                            <div class="detail-description row">
                                <div class="col col-8">
                                    <div class="card description-info">
                                        <div class="m-b-15">
                                            <div class="default-title">
                                                <h4>Description</h4>
                                            </div>
                                        </div>
                                        <product-body-html :data="data.body_html"></product-body-html>
                                    </div>

                                    <!--// not in this version-->
                                    <!--<div class="card description-info m-t-20">-->
                                    <!--<div class="m-b-15">-->
                                    <!--<div class="default-title">-->
                                    <!--<h4 >Question</h4>-->
                                    <!--</div>-->
                                    <!--</div>-->
                                    <!--<div class="question-body">-->
                                    <!--<product-question :product-id="data.id"></product-question>-->
                                    <!--</div>-->
                                    <!--</div>-->
                                    <!--//-->

                                </div>
                                <div class="col col-4" v-if="listBestSelling.length">
                                    <div class="card best-selling">
                                        <div class="m-b-15">
                                            <div class="default-title">
                                                <h4>Best Selling</h4>
                                            </div>
                                        </div>
                                        <div>
                                            <ul class="list-product">
                                                <li class="product-item" v-for="(item , index) in listBestSelling"
                                                    :key="`selling_${index}`">
                                                    <router-link class="product-image"
                                                                 :to="{ name : 'ProductDetail' , params: { id : `${item.handle}-${item.id}`}}">
                                                        <img v-if="item.image" :src="item.image" alt="">
                                                        <img v-else src="@/assets/images/default/product.png" alt="">
                                                    </router-link>
                                                    <div class="product-content">
                                                        <router-link v-line-clamp:20="2" class="product-title"
                                                                     :to="{ name : 'ProductDetail' , params: { id : `${item.handle}-${item.id}`}}">
                                                            {{item.title}}
                                                        </router-link>
                                                        <div class="product-supplier-and-price">
                                                            <div class="product-supplier">
                                                                <p><span>By</span><a href="">{{item.shop_name}}</a></p>
                                                            </div>
                                                            <div class="product-price">
                                                                <span v-if="item.price_min === item.price_max">${{item.price_max | number_format}}</span>
                                                                <span v-else>${{item.price_min | number_format}} - ${{item.price_max | number_format}}</span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </li>
                                            </ul>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="product-foot">
                        <div class="container">
                            <div class="row">
                                <div class="col col-12">
                                    <list-product-filter title="Recent Viewed Product" mode="recent" :limit="5"
                                                         col="col col-20 m-b-20"></list-product-filter>
                                </div>
                            </div>
                        </div>
                    </div>
                </template>
            </div>
        </transition>
    </div>
</template>
<script>
    import {mapActions, mapGetters} from 'vuex'
    import ImageZoomer from '@/modules/home/_components/partials/vue-pic-zoom'
    import {Carousel, Slide} from '@/components/v-carousel'
    import ProductBodyHtml from '../partials/product-body-html'
    import BestSellingProduct from '../partials/product-best-selling'
    import ListProductFilter from '../partials/list-product-filter'
    import Error from '@/components/error-404'
    import helper from '@/plugins/helper'
    import mixin from '@/modules/home/_mixins/product-detail'
    import breadcrumb from '../partials/collection-breadcrumb'
    import ProductQuestion from '../partials/product-question'
    import ListFlag from '../partials/list-flag'

    export default {
        name: 'ProductDetail',
        mixins: [mixin],
        components: {
            ImageZoomer,
            Carousel,
            Slide,
            ProductBodyHtml,
            BestSellingProduct,
            ListProductFilter,
            Error,
            breadcrumb,
            ProductQuestion,
            ListFlag
        },
        metaInfo() {
            return {
                title: this.meta.title,
                meta: [
                    {
                        'name': 'og:type',
                        'vmid': 'og:type',
                        'property': 'og:type',
                        'content': 'product'
                    },
                    {
                        'name': 'og:url',
                        'vmid': 'og:url',
                        'property': 'og:url',
                        'content': this.meta.url
                    },
                    {
                        'name': 'og:title',
                        'vmid': 'og:title',
                        'property': 'og:title',
                        'content': this.meta.title
                    },
                    {
                        'name': 'og:description',
                        'vmid': 'og:description',
                        'property': 'og:description',
                        'content': this.meta.title
                    },
                    {
                        'name': 'og:image',
                        'vmid': 'og:image',
                        'property': 'og:image',
                        'content': this.meta.image
                    },
                ]
            }
        },
        data() {
            return {
                isContentOverFlow: true,
                listBestSelling: [],
                data: null,
                isLoading: false,
                error: null,
                isImportLoading: false,
                meta: {
                    title: '',
                    url: '',
                    image: '',
                    description: '',
                    type: ''
                }
            }
        },
        methods: {
            ...mapActions({
                getProductDetail: "$_Home/GET_PRODUCT_DETAIL",
                getListBestSelling: "$_Home/GET_LIST_BEST_SELLING",
                callImportProduct: "$_Home/IMPORT_PRODUCT"
            }),
            ...mapGetters({
                seller: '$_Seller/getSeller',
            }),
            importProduct(product, event) {
                if (this.seller()) {
                    let id = product.id
                    let target = $(event.target)
                    this.isImportLoading = true
                    let defaultShop = this.seller().shops.filter(function (el, idx) {
                        return el.shop_default == 1
                    });
                    let temp = {
                        "product_id": id,
                        "shop_id": defaultShop[0].id
                    }
                    this.callImportProduct(temp).then(res => {
                        if (res.data.status) {
                            this.ProductInfo.isImported = true
                        } else {
                            $notify({
                                content: 'import product fail',
                                type: 'danger'
                            })
                        }
                        this.isImportLoading = false
                    })
                } else {
                    this.$router.push({
                        name: "Login"
                    })
                }
            },
            removeImported(product) {
                let id = product.id
                let target = $(event.target)
                this.isLoading = true
                let defaultShop = this.seller().shops.filter(function (el, idx) {
                    return el.shop_default == 1
                });
                let temp = {
                    "product_id": id,
                    "shop_id": defaultShop[0].id
                }
                this.removeImportedProduct(temp).then(res => {
                    if (res.data.status) {
                        this.ProductInfo.isImported = false
                    } else {
                        $notify({
                            content: 'Remove Imported Product fail',
                            type: 'danger'
                        })
                    }
                    this.isLoading = false
                })
            },
            saveToRecent: function (id) {
                let ids = this.getLocalStore("lr")
                if (ids) {
                    ids = ids.filter((item) => {
                        return item != id
                    })
                    if (ids.length >= 50) {
                        ids.shift()
                    }
                } else {
                    ids = []
                }
                ids.push(id)
                this.setLocalStore('lr', ids)
            },
            sticky_detail_bar() {
                var navbar = $(this.$refs.sticky)
                var body = $(this.$refs.body)
                if (navbar) {
                    var stickyNavTop = body.outerHeight()
                    var stickyNav = function () {
                        var scrollTop = $(window).scrollTop();
                        if (scrollTop > stickyNavTop) {
                            navbar.addClass('sticky');
                        } else {
                            navbar.removeClass('sticky');
                        }
                    };
                    stickyNav();
                    $(window).scroll(function () {
                        stickyNav();
                    });
                }
            },
            product_detail_init(id) {
                return new Promise(async (reslove, reject) => {
                    this.isLoading = true
                    var productValid = null
                    var product = await this.getProductDetail({id})
                    if (product) {
                        let {status, data, message} = product
                        if (status) {
                            if (data) {
                                this.saveToRecent(id)
                                this.data = data
                                productValid = true

                            } else {
                                this.error = `Product Not Available`
                            }
                        } else {
                            this.error = 'Something went wrong !'
                        }
                    }
                    this.isLoading = false
                    this.$nextTick(() => {
                        setTimeout(() => {
                            this.sticky_detail_bar()
                        }, 600);
                    })

                    if (productValid) {
                        let listBestSelling = await this.getListBestSelling(id)
                        if (listBestSelling) {
                            let {status, data, message} = listBestSelling
                            if (status) {
                                this.listBestSelling = data
                            }
                        }
                    }
                    reslove()
                })
            },
            setMeta() {
                if (this.error) {

                } else {
                    this.meta.title = this.data.title
                    this.meta.url = `${this.data.handle}-${this.data.id}`
                    this.meta.image = this.data.images.length ? this.data.images[0].src : ''
                }
            },
        },
        computed: {
            ...mapGetters({
                collections: '$_Home/getCollections',
                countries: '$_Home/getCountries',
                base_url: 'getBaseUrl'
            }),
            breadcrumb() {
                if (this.data) {
                    var collection_id = this.data.collection_id
                    var collection = helper.findDeep(this.collections, 'id', (item, id) => id == collection_id)
                    if (collection) {
                        if (collection.level == 1) {
                            return [
                                {
                                    id: collection.id,
                                    title: collection.title,
                                }
                            ]
                        } else if (collection.level == 2) {
                            var title = []
                            var level1 = helper.findDeep(this.collections, 'id', (item, id) => id == collection.parent_id)
                            if (level1) {
                                title.push({
                                    id: level1.id,
                                    title: level1.title
                                })
                            }
                            title.push({
                                id: collection.id,
                                title: collection.title
                            })
                            return title
                        } else if (collection.level == 3) {
                            var title = []
                            var level2 = helper.findDeep(this.collections, 'id', (item, id) => id == collection.parent_id)
                            if (level2) {
                                var level1 = helper.findDeep(this.collections, 'id', (item, id) => id == level2.parent_id)
                                if (level1) {
                                    title.push({
                                        id: level1.id,
                                        title: level1.title
                                    })
                                }
                                title.push({
                                    id: level2.id,
                                    title: level2.title
                                })
                            }
                            title.push({
                                id: collection.id,
                                title: collection.title
                            })
                            return title
                        }

                    }
                }
                return []
            },
            productShippings() {
                if (this.data) {
                    var warehouses = JSON.parse(JSON.stringify(this.data.warehouses))
                    warehouses = warehouses.map((item) => {
                        item['shippings'] = []
                        return item
                    })
                    for (var key in this.data.shippings) {
                        if (this.data.shippings.hasOwnProperty(key)) {
                            const item = this.data.shippings[key]
                            item.forEach((shipping) => {
                                var index = _.findIndex(warehouses, {id: shipping.warehouse_id})
                                if (index >= 0) {
                                    if (shipping.rest_of_countries == 0) {
                                        var country_code = shipping.country_code;
                                        var split = country_code.split(',')
                                        shipping['countries'] = country_code.split(',').map((item) => {
                                            var code = _.find(this.countries, {code: item})
                                            return code
                                        }).filter(item => item != undefined)
                                    }
                                    warehouses[index].shippings.push(shipping)
                                }
                            })
                        }
                    }
                    return warehouses.filter((item) => {
                        return item.shippings.length
                    })
                }
                return []
            }
        },
        beforeRouteUpdate: async function (to, from, next) {
            let id = this.getSlugId(to.fullPath);
            await this.product_detail_init(id)
            this.setMeta()
            next()
        },
        created: async function () {
            let to = this.$route
            let id = this.getSlugId(to.fullPath);
            await this.product_detail_init(id)
            this.setMeta()
        },
    }
</script>
<style lang="scss" scoped>
    @import 'src/assets/style';

    $border-color: #eee;
    .product-detail-container {
        &-loading {
            min-height: 500px;
            display: flex;
            justify-content: center;
            align-items: center;
            .icon-loading {
                height: 60px;
                width: 60px;
                background: $yellow;
            }
        }
        .overflow-text {
            display: block;
            display: -webkit-box;
            -webkit-box-orient: vertical;
            overflow: hidden;
            text-overflow: ellipsis;
        }
        .product-detail-sticky-bar {
            opacity: 0;
            background: white;
            transition: all 0s;
            border-bottom: solid 1px lightgray;
            box-shadow: 0px 1px 7px 0px rgba(0, 0, 0, 0.2);
            .detail-sticky {
                display: flex;
                justify-content: space-between;
                flex-flow: row wrap;
                height: 60px;
                .sticky-bar-item {
                    line-height: 60px;
                    display: flex;
                    .product-name {
                        font-size: 22px;
                        max-width: 450px;
                        /*flex: 1;*/
                        @extend .overflow-text;
                        -webkit-line-clamp: 1;

                    }
                    .supplier-name {
                        font-size: $default-font-size;
                    }
                    .product-price {
                        font-weight: bold;
                        font-size: 22px;
                    }
                    .product-old-price {
                        color: lightgray;
                        font-size: $default-font-size;
                        text-decoration: line-through;
                    }
                    .product-old-price, .product-price {
                        vertical-align: middle;
                    }
                    .import-actions {
                        .btn-importing {
                            .icon-load {
                                display: none;
                            }
                            .circle-loader {
                                display: inline-block;
                            }
                        }
                    }
                }
            }
        }
        .detail-description {
            div.layout-item:nth-child(1) {
                padding-right: 10px;
            }
            div.layout-item:nth-child(2) {
                padding-left: 10px;
            }
            .description-info {
                padding: 40px 40px 20px;
            }
            .best-selling {
                padding: 40px 30px 30px;
            }
            .best-selling {
