import actions from './actions';
import getters from './getters';
import mutations from './mutations';
const token = localStorage.getItem('token')
const token_expired = localStorage.getItem('token_expired')
const remember = localStorage.getItem('remember') 
let remember_timeout = parseInt(process.env.VUE_APP_REMEMBER_TIMEOUT) * 1000
const state = {
    searchValue: '' ,
    token : token,
    token_expired : token_expired ? parseInt(token_expired) : null ,
    isLoggedIn : token ? true : false,
    seller : null , 
    remember : remember ? JSON.parse(remember) : false ,
    remember_timeout : parseInt(remember_timeout) ,
};

const moduleStore = {
    namespaced: true,
    state,
    actions,
    getters,
    mutations,
}
const moduleName = 'Seller'

export {
    moduleStore , moduleName
};
