        <carddialog v-if="!isNotAuto" :isShow="isCardDialogShow" @modalHide="isCardDialogShow=false" @dialogConfirm="createCardForCustomer"></carddialog>
    </div>
</template>

<script>
    import {mapActions} from 'vuex'
    import carddialog from './card-dialog'

    export default {
        name: "pricing",
        props: ['current_plan', 'isNotAuto'],
        data() {
            return {
                selected_plan: '',
                isCardDialogShow: false
            }
        },
        components: {
            carddialog
        },
        methods: {
            ...mapActions({
                getUserInfo: "$_Seller/GET_USER_INFO",
                requestChoosePlan: "$_Seller/SELLER_CHOOSING_PLAN",
                createCustomer: "$_Seller/CREATE_CUSTOMER",
            }),
            createCardForCustomer(cardInfo) {
                let democart = {
                    "card_no": cardInfo.card_no.replace(/\W/gi, ''),
                    "ccExpiryMonth": cardInfo.expire_date.split('/')[0],
                    "ccExpiryYear": cardInfo.expire_date.split('/')[1],
                    "cvvNumber": cardInfo.secure_code,
                    "plan_id": this.selected_plan
                }
                console.log(democart);
                this.isCardDialogShow = false
                this.createCustomer(democart).then(res => {
                    if (res.data.status) {
                        $notify({
                            content: "Change plan success",
                            type: "success"
                        })
                    } else {
                        this.isCardDialogShow = true
                        $notify({
                            content: res.data.message,
                            type: "danger"
                        })
                    }
                })
            },
            choosePlan: function (plan) {
                if (this.isNotAuto) {
                    this.$emit('choose_plan', plan)
                } else {
                    this.requestChoosePlan(plan).then(res => {
                        if (res.data.status) {
                            this.initPlan()
                            $notify({
                                content: "Success",
                                type: "success"
                            })
                        } else {
                            // this.selected_plan = plan
                            this.isCardDialogShow = true
                        }
                    })
                }
            },
            initPlan() {
                if (!this.current_plan) {
                    this.getUserInfo().then(res => {
                        if (res.data.status) {
                            console.log(res.data.data);
                            this.selected_plan = res.data.data.plan_name
                        } else {
                            $notify({
                                content: "Load Seller info Fail",
                                type: "danger"
                            })
                        }
                    })
                } else {
                    this.selected_plan = this.current_plan
                }
            }
        },
        created: function () {
            var seller = this.$store.getters['$_Seller/getSeller']
            if( seller){
                this.selected_plan = seller.plan_name
            }else{
                this.selected_plan = this.current_plan
            }
        },
        watch: {
            "current_plan": function (value) {
                this.selected_plan = value
            }
        }
    }
</script>

