export default {
    getLang(state){
        return state.lang ;
    },
    baseUrl(state){
        return state.base_url
    },
    getRouter(state){
        return state.router
    },
    getPreviousRouter(state){
        return state.previousRouter
    },
    getFacebookAppID(state){
        return state.facebook_app_id
    },
    getGoogleAppID(state){
        return state.google_app_id
    }
}